INSERT INTO public.passages VALUES ('0299a616-be81-4608-a7f2-cf51ca78b534', '3227059f-1374-40c3-9016-3cbd412569b3', 'Part 2', '', 0, NULL, NULL, 11);
INSERT INTO public.passages VALUES ('2c3ad16d-88b5-497f-a8ce-bc9b03da1423', '4c9a32d8-cfef-4922-a625-fb5e0caaeab9', 'PASSAGE 1', '<h3><strong>Jethro Tull (1674–1741) – Inventor of the Seed Drill</strong></h3>
<p><em>The English gentleman farmer who revolutionized the practice of agriculture</em></p>
<p>Jethro Tull was a major pioneer in the modernizing of agriculture. He was born in 1674 in Berkshire, southern England, into a family of land-owning gentry. He studied first at Oxford University and then at the Inns of Court, London, in preparation for a legal or political career. However, his health issues forced him to postpone these plans, and after qualifying as a barrister in 1699, he made a tour of Europe, in the hope that the milder climates of France and Italy would alleviate his breathing problems. In every country through which he passed, he made careful observations of the soil and agricultural production, and on his return to England, the young Tull married, then began farming with his father at Howberry farm in Oxfordshire.</p>
<p>Tull was determined to improve farming methods and increase crop yield on the family land, and pursued a number of agricultural experiments. He particularly wanted to increase efficiency in the sowing of seeds. At that time, seeds were still thrown by hand across the field in a haphazard manner, in a traditional method known as broadcasting. Tull soon realized this method of random distribution was inefficient, being wasteful of both seed and labor, so he instructed his staff to sow seeds at very precise, low densities. But by 1701, his frustration with their lack of co-operation prompted him to invent a machine to do the work for him.</p>
<p>Earlier in his life, Tull had once dismantled a pipe-organ, and the application of the technology behind this musical instrument inspired him to devise a drill that would distribute precise amounts of seed into pre-cut channels. Basic seeding devices had been known for almost 2000 years, but Tull took the concept a stage further. In his device, as the main wheels of the drill turned, the cylinder rotated against a spring-held tongue. This allowed seed to pass evenly from the hopper above to a funnel below. From here, the seed was directed at regular intervals into three channels, or furrows, in the earth. These were dug to a specific depth by the blades at the front of the machine. Spikes at the back of the machine then turned the soil over to immediately cover the seeds. Tull’s ‘seed drill’ would limit the wastage of seed, and as the seedlings grew in uniform rows, it would also make it easier to remove any unwanted weeds growing among the crop. Accordingly, each plant would have more space to grow, and although there would be fewer plants, the net yield would be greater.</p>
<p>Initially the machine was only a limited success, and in 1711 Tull decided to travel around Europe again, both to improve his health and to study agricultural techniques there. Upon his return in 1714, he perfected both his system and machinery. Following practices he had observed in the vine-growing methods of southern Europe, he used an animal-drawn hoe to turn over and pulverize the earth between the rows. He wrongly believed this practice would release enough nutrients in the soil to nourish the crop, and so eliminate the need for manure to be used to fertilize the soil. His experiments were apparently successful, as he did manage to grow wheat in the same field for 13 successive years without the use of manure. However, it is more likely that it was the turning over and pulverization of the soil that cut down on the volume of weeds competing with the seed.</p>
<p>Tull’s complete system eventually proved to be a major influence in the agricultural revolution, and its impact can still be seen in today’s methods. Most subsequent drilling and hoeing implements have been either copies of, or improvements upon his inventions, and his modifications to the basic model of the plough continue to be visible in modern versions. Tull also advocated the use of horses over the oxen more traditionally used to pull farm machinery, and published a book in 1731 outlining this and other ideas to enhance agricultural efficiency. The book caused great controversy when it appeared, and resistance to his revolutionary theories persisted for many decades. Another century would pass before his eventual vindication. It was only following the editing of his writings in 1822, and the subsequent translations and acceptance in France, that Tull’s ideas finally achieved recognition in his native land. Although in his lifetime, Tull’s methods and inventions were dismissed and ridiculed, they were gradually adopted by large landowners, and in time, came to form the basis of modern agriculture.</p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('2a59950a-dfd8-4aaa-9464-37388e2b4424', '72332d08-23b4-447a-b46d-430d389c45d3', 'Passage 2', '<p><strong><span style="font-size: 14pt;">Born to Trade</span></strong></p>
<p><em>Long before our ancestors had any trappings of civilization, they had a taste for material goods. Kate Douglas discovers where this ancient obsession has led us.</em></p>
<p>{iv A natural human talent}</p>
<p>Humans are born to trade, and we don’t need shops or money to do it—the heart of commerce is an instinctive ability for what anthropologists call reciprocity. This is an ability to exchange goods of equal worth, and it evolved as the brains of our ancient ancestors and societies became more complex, allowing individuals to keep a running tally of their interactions with others. Evidence from modern hunter-gatherers leaves little doubt that the exchange of food and flavors is innate, as is the ability to keep track of the credits and debits that accrue as a result. Combine this skill for mental bookkeeping with even the most basic material culture, and trade inevitably follows.</p>
<p>{iii Querying the changes in the value of traded items}<span style="font-size: 14px;"> </span></p>
<p>Once trade gets off the ground, the economic benefits quickly make it irresistible. But exchanging tools, food, and other essentials of life in a barter economy is a far cry from the shopping mall. Modern consumerism sways beyond subsistence and utilitarianism to encompass everything from Gucci handbags and BMW convertibles to valuable paintings. Clearly, the worth of such goods is not inherent but resides in certain intangible qualities that we invest in them. When did humans start holding these goods in such high esteem?</p>
<p><strong> {vi. Recent finds alter theories about when consumerism started}</strong></p>
<p>All the archaeological evidence for the flowering of consumer culture has, up to now, pointed to a date of around 40,000 years ago. That’s when early modern humans started making increasingly intricate bone and stone tools, carving patterns into rocks, and creating representational art such as carved figurines, jewelry, and cave paintings. However, discoveries in Africa are pushing the origins of consumerism much further back into human prehistory.</p>
<p>A few years ago, reports began to emerge of discoveries made at the Blombos cave, a site of ancient human habitation in South Africa. Christopher Henshilwood and colleagues from the University of Bergen in Norway dated thousands of pieces of ochre from the cave, and many of them proved to be more than 100,000 years old—before the time that early humans moved out of Africa. Ochre, a colored clay that comes in various shades from red to black, does not occur naturally around Blombos and must have been imported from quarries at least 30 kilometers away, either directly by Blombos residents or through trade. Although ochre can be used to dry and preserve (or “cure”) animal hides, the researchers are convinced the Blombos ochre had a symbolic purpose. For a start, it is predominantly red—any of the other colors available would have sufficed for curing—and the surfaces of the clay had been scraped in a way that indicates they were used to yield pigment for dyes.</p>
<p>{ii The clues that indicate ancient items were decorative}</p>
<p>An even more intriguing discovery from Blombos was of 41 beads dating from 76,000 years ago, found in clusters and made from the shells of a tiny mollusk. These cannot be natural deposits, argue the researchers, as each cluster contains shells of a similar size and color with consistently placed holes. What’s more, all the beads display a pattern of wear suggesting friction from rubbing against thread, clothes, or other beads.</p>
<p>The previous oldest find of beads in Africa dates back to just 45,000 years ago. And it seems the Blombos people’s taste for beautiful items was not an isolated phenomenon. Jessica Thompson of Arizona State University in Tempe has described finding shell fragments from a site in Tanzania that she believes may represent debris from bead manufacture. They are at least 45,000—and possibly 280,000—years old. Although there is no evidence of how the ancient beads were used, their modern counterparts are often traded. So it looks as though our taste for jewelry and art is much older than we thought.</p>
<p>{v How status can be gained from ownership of goods}</p>
<p>But why did we come to value these objects in the first place? In many animal species, individuals signal their genetic fitness by showing off with attention-grabbing adornment. Some researchers think that in humans, consumer products play a similar role. Archaeologist Aimee Plourde, from the University of California, also argues that even in egalitarian societies, some people are more successful than others. Among our ancestors, superior skills in areas such as hunting, crafts, environmental knowledge, and contact with neighboring groups would have brought respect—in other words, prestige.</p>
<p>And because prestige brings social benefits, people would want to show off their talents. The best way to do this would be through demonstrating possession of material items that are hard to fake. “A good hunter, for instance, could advertise his skills by wearing the tooth of an animal that is elusive or dangerous,” says Plourde. The benefits of prestige would also lead to competition to acquire it. As a result, the value and variety of prestige goods would spiral, and there would be a parallel increase in the ranking of social systems.</p>
<p>If Plourde is correct, prestige goods form a direct link between our innate drive for trade and the development of structured, hierarchical societies. They are arguably the first step on the road to modern civilization, paving the way for agriculture and urbanization. We may not be impressed by beads anymore, but their modern equivalents have the same fascination. Nobody believes the guy who spends €670,000 on a Bugatti Veyron car does so because he needs to travel at 250 mph. We all know in today’s consumer society he’s buying an exclusive status symbol.</p>', 0, NULL, NULL, 14);
INSERT INTO public.passages VALUES ('aa8132aa-4cfc-4f48-9552-a816e6b5e417', '1e03e36e-c43a-40ba-b699-41e54fb03250', 'Passage 1', '<p><strong>Ambergris – what is it and where does it come from?</strong></p>
<p>In the ancient world, the waxy grey substance we now refer to as ambergris was highly prized for its medicinal properties, and was widely used as a spice, which was believed to be an aphrodisiac when added to food or wine. Ambergris itself is pleasantly aromatic, especially when warmed, and it was also highly valued as a fixing agent in the making of perfume, since it enabled a scent to retain its fragrance for much longer than might otherwise have been possible. Most ambergris was found in the form of lumps floating on the surface of the sea, or washed up on the shores of tropical and temperate oceans. At one time, ambergris was worth its weight in gold, but there was much confusion about its origins.</p>
<p>Ambergris was known to the Arabs as ‘ambar’ and was originally called amber in the West in the Middle Ages. This eventually led to further confusion in the popular mind between ambergris and true amber, the mineral known to mineralogists as succinite, which is actually fossilised tree resin, and generally yellow in colour. Both substances were rare and costly, and both were associated with the sea, largely because for Europeans the most common source of amber was the shores of the Baltic. In Chapter 92 of Moby Dick, the American writer Herman Melville pours scorn on those who believed the two substances to be the same:</p>
<p>“Though the word ambergris is but the French compound for grey amber, yet the two substances are quite distinct. For amber, though at times found on the sea-coast, is also dug up in some far inland soils, whereas ambergris is never found except upon the sea. Besides, amber is a hard, transparent, brittle, odorless substance, used for mouth-pieces to pipes, for beads and ornaments; but ambergris is soft, waxy, and so highly fragrant that it is largely used in perfumery.”</p>
<p>Moby Dick was published in 1851, by which time the mystery of the origins of ambergris had been resolved by the scientific community. In 1783, the botanist Joseph Banks, who had accompanied Captain James Cook on his voyages of discovery in the Pacific, presented a paper to the Royal Society of London by the German physician Dr. Franz Xavier Schwediawer in which it was conclusively proved that ambergris came from sperm whales. In this, he was confirming an observation made in the 13th century by the great Venetian traveller Marco Polo who, while on the island of Socotra in the Indian Ocean, had witnessed a sperm whale vomiting up ambergris. But whereas Marco Polo imagined that the whale had swallowed the lump in the depths of the sea, Schwediawer showed that the origin of the material was inside the whale itself.</p>
<p>The sperm whale is the largest of the odontocetes, or toothed whales. Males can grow up to 20 meters in length. Melville described the sperm whale as the ‘king of whales’, and his novel Moby Dick is based on the pursuit of one such creature. Sperm whales are renowned for their ability to dive to great depths, possibly as far as 3,000 metres below the surface, and for remaining underwater for periods of two hours or more in pursuit of their favourite prey, the giant squid.</p>
<p>It is from the problems the whales have in digesting the beaks of such creatures that ambergris has its origins. The beak is sharp and irritates the whale’s lower intestine, which responds by producing a black, foul-smelling liquid. It is not clear to scientists whether this secretion should be considered a normal response by the whale’s digestive system or a pathological one, but from time to time large quantities of the liquid are vomited up by the whale. Once outside the whale’s body and exposed to air, the substance hardens, acquiring the waxy, greyish and pleasantly aromatic characteristics of ambergris. Often the beaks of squid are still found embedded in lumps of ambergris, some of which can weigh several hundred kilograms. Melville took some delight in contrasting the origins of ambergris with the high value placed upon it by refined society:</p>
<p>“Who would think, then, that such fine ladies and gentlemen should regale themselves with an essence found in the inglorious bowels of a sick whale!”</p>
<p>Sperm whales were ruthlessly pursued by commercial whalers in the 19th and 20th centuries. In 1963-64 alone, almost 30,000 individuals were killed, and only the imposition of a ban on the hunting of sperm whales in 1984 saved the species from extinction. Ambergris was by far the most valuable product to be extracted during the processing of the whales’ carcasses, and over 90 per cent of the annual worldwide total was acquired in this way, as a by-product of commercial whaling. However, even before the ban on hunting sperm whales was imposed, the 1972 Marine Mammal Protection Act had prohibited trade in ambergris. Just as petroleum and plastic products were replacing other natural products of whaling, so ambergris was supplanted in the making of perfume by other materials, some natural and some synthetic in origin. Nevertheless, it is possible that, as sperm whale populations recover to their former numbers in the wild, so the sight of lumps of ambergris washed ashore along the tide line will once again become a familiar one to beachcombers the world over.</p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('542b2040-3f68-499d-a7b0-f76d6580181c', '2c6cc65e-d5a0-42d2-9ef9-ff3808dc3789', 'READING PASSAGE 1', '<p style="text-align: left;" data-start="75" data-end="176">You should spend about 20 minutes on <strong data-start="112" data-end="131">Questions 14–26</strong>, which are based on Reading Passage 2 below.</p>
<p style="text-align: left;" data-start="183" data-end="210"><span style="font-size: 14pt;"><strong data-start="183" data-end="210">REMOVING UNWANTED NOISE</strong></span></p>
<p style="text-align: left;" data-start="212" data-end="741"><strong data-start="212" data-end="217">{v. A drawback in the help currently available to those with hearing problems}     </strong></p>
<p style="text-align: left;" data-start="212" data-end="741">A noisy restaurant, a busy road, or a windy day are all situations that can be intensely frustrating for the hearing impaired when trying to understand what other people are saying. Some 10 million people in the UK suffer from hearing difficulties and, helpful as hearing aids are, those who wear them often complain that background noise continues to interfere with their understanding. But what if hearing aid wearers could choose to filter out all the troublesome sounds and focus just on the voices they want to hear?</p>
<p style="text-align: left;" data-start="743" data-end="1375">Engineer Dr Richard Turner believes that this is fast becoming a possibility. He is developing a system that identifies the distracting noise and ‘rubs it out’. ‘The poor performance in noise of current hearing devices is a major reason why six million people in the UK who would benefit from hearing aids do not use them,’ he said. Moreover, as the population ages, a greater number of people will be hindered by the inability to hear clearly. In addition, hearing-impaired patients who have been fitted with cochlear implants – devices implanted to help those whose auditory hair cells have died – suffer from similar limitations.</p>
<p style="text-align: left;" data-start="1377" data-end="2039"><strong data-start="1377" data-end="1382">{iii. Creating a model for the classification of sounds}    </strong></p>
<p style="text-align: left;" data-start="1377" data-end="2039">The solution lies in the statistics of sound, as Turner explained: ‘Many interfering noises are immediately recognisable. Raindrops patter on a surface, a fire crackles, talkers babble at a party and the wind howls. But what makes these different noises sound the way they do? No two rain sounds are identical because the precise arrangement of falling water droplets is never repeated. Nonetheless, there must be statistical similarities in the sounds of these raindrops compared with, say, the crackle of a fire.’ He believes that for this reason, the brain may be able to group similar types of sounds together based on their specific characteristics.</p>
<p style="text-align: left;" data-start="2041" data-end="2638">Turner and his colleagues have analysed this process mathematically and then developed algorithms that mimic what the brain is doing. The mathematical system that they have developed is capable of being ‘trained’ — a process that uses new methods from the field of machine learning — so that it can recognise new sounds. ‘Rather surprisingly, it seems that a relatively small set of statistics is sufficient to describe a large number of sounds’ he says. Crucially, the system that Turner and his team have come up with is capable of telling the difference between speech and other types of sound.</p>
<p style="text-align: left;" data-start="2640" data-end="3202" data-is-last-node="" data-is-only-node=""><strong data-start="2640" data-end="2645">{ix. The possibility of a hearing aid that can adjust itself to different environments}     </strong></p>
<p style="text-align: left;" data-start="2640" data-end="3202" data-is-last-node="" data-is-only-node="">‘What we can now do is to erase background noise and pass these cleaned-up sounds to a listener to improve their perception in difficult surroundings,’ said Turner. The idea is that future devices will have several different modes in which they can operate. These might include a mode for travelling in a car or on a train, a mode for places like a noisy party or a busy restaurant, a mode that can be used outdoors in windy weather, and so on. The device might intelligently select an appropriate mode based on the characteristics of the incoming sound.</p>
<article class="text-token-text-primary w-full" dir="auto" data-testid="conversation-turn-297" data-scroll-anchor="false">
<div class="text-base my-auto mx-auto py-5 [--thread-content-margin:--spacing(4)] @[37rem]:[--thread-content-margin:--spacing(6)] @[72rem]:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:32rem] @[34rem]:[--thread-content-max-width:40rem] @[64rem]:[--thread-content-max-width:48rem] mx-auto flex max-w-(--thread-content-max-width) flex-1 text-base gap-4 md:gap-5 lg:gap-6 group/turn-messages focus-visible:outline-hidden" tabindex="-1">
<div class="group/conversation-turn relative flex w-full min-w-0 flex-col agent-turn">
<div class="relative flex-col gap-1 md:gap-3">
<div class="flex max-w-full flex-col grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-5" dir="auto" data-message-author-role="assistant" data-message-id="66af3cd1-dae1-40a8-9685-e545fe79fb3b" data-message-model-slug="gpt-4o">
<div class="flex w-full flex-col gap-1 empty:hidden first:pt-[3px]">
<div class="markdown prose dark:prose-invert w-full break-words light">
<p data-start="56" data-end="816"><strong data-start="56" data-end="61">{iv. Potential developments that still require further research}    </strong></p>
<p data-start="56" data-end="816">‘In a sense we are developing the technology to underpin intelligent hearing devices,’ said Turner. An additional possibility would be for users to override the selection made by the device and select a processing mode based upon what sorts of noise they wish to erase. They could even guide the processing on their device using an interface on a mobile phone through wireless communication. Turner anticipates that his team will need two more years of simulating the effect of modifications that clean up sound before they start to work with device specialists. ‘If these preliminary tests go well, then we’ll be looking to work with hearing device companies to try to adapt their processing in order to incorporate these machine learning techniques.’</p>
<p data-start="818" data-end="1315"><strong data-start="818" data-end="823">{vii. A more effective way to take attention away from a hearing problem}    </strong></p>
<p data-start="818" data-end="1315">Tinnitus sufferers, who are plagued by a constant ringing in their ears, could also benefit from the technology. At present, people with tinnitus sometimes use environmental sound generators as a distraction from the ringing in their ears. But such generators offer only a limited selection of sounds — a gently flowing stream, waves lapping on the seashore, or leaves rustling. With the new technology, individual patients could select the best sound to distract them from their tinnitus.</p>
<p data-start="1317" data-end="1999" data-is-last-node="" data-is-only-node=""><strong data-start="1317" data-end="1322">{ii. Uses for Turner’s research in media and communications}   </strong></p>
<p data-start="1317" data-end="1999" data-is-last-node="" data-is-only-node="">The technology not only holds promise for helping the hearing impaired, but it also has the potential to improve phone calls — anyone who has ever tried to hold a conversation with someone phoning from a crowded room will recognise the possible benefits of such a facility. Systems that can deal with unwanted audio content would also be welcomed by the increasing numbers of people using video-sharing websites. For example, a video containing a conversation that takes place by a busy roadside on a windy day could be made more intelligible by isolating the speech from the noises — users could even be offered the chance to de-noise their video during the upload process.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</article>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('a3611f3d-1993-46d2-961c-4d320a323d1d', 'b5f2547d-b626-4034-b03c-63d4bf05b25a', 'Part 4', '<p>Complete the notes below.</p>', 0, NULL, NULL, 31);
INSERT INTO public.passages VALUES ('9e74c3bb-ed43-4df5-bbd1-f548be9e70f2', '88d158a0-fdb8-4aab-b316-6f8388977bb1', 'PASSAGE 1', '<p style="text-align: left;"><span style="font-size: 14pt;"><strong>Biomimetic Design</strong></span></p>
<p style="text-align: left;"><span style="font-size: 12pt;">What has fins like a whale, skin like a lizard, and eyes like a moth? The future of engineering. Andrew Parker, an evolutionary biologist, knelt in the baking red sand of the Australian outback just south of Alice Springs and eased the right hind leg of a thorny devil into a dish of water.</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>A</strong>     </span><span style="font-size: 12pt;">“Its back is completely drenched!” Sure enough, after 30 seconds, water from the dish had picked up the lizard’s leg and was glistening all over its prickly hide. In a few seconds more the water reached its mouth, and the lizard began to smack its jaws with evident satisfaction. It was, in essence, drinking through its foot. Given more time, the thorny devil can perform this same conjuring trick on a patch of damp sand – a vital competitive advantage in the desert. Parker had come here to discover precisely how it does this, not from purely biological interest, but with a concrete purpose in mind: to make a thorny-devil-inspired device that will help people collect lifesaving water in the desert. “The water’s spreading out incredibly fast!” he said, as drops from his eyedropper fell onto the lizard’s back and vanished, like magic. “Its skin is far more hydrophobic than I thought. There may well be hidden capillaries, channeling the water into the mouth.”</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>B</strong>     </span><span style="font-size: 12pt;">Parker’s work is only a small part of an increasingly vigorous, global biomimetics movement. Engineers in Bath, England, and West Chester, Pennsylvania, are pondering the bumps on the leading edges of humpback whale flukes to learn how to make airplane wings for more agile flight. In Berlin, Germany, the fingerlike primary feathers of raptors are inspiring engineers to develop wings that change shape alot to reduce drag and increase fuel efficiency. Architects in Zimbabwe are studying how termites regulate temperature, humidity, and airflow in their mounds in order to build more comfortable buildings, while Japanese medical researchers are reducing the pain of an injection by using hypodermic needles edged with tiny serrations, like those on a mosquito’s proboscis, minimizing nerve stimulation.</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>C</strong>     </span><span style="font-size: 12pt;">Ronald Fearing, a professor of electrical engineering at the University of California, Berkeley, has taken on one of the biggest challenges of all: to create a miniature robotic fly that is swift, small, and maneuverable enough for use in surveillance or search-and-rescue operations. Fearing made his own, one of which he held up with tweezers for me to see, a gossamer wand some 11 millimeters long and not much thicker than a cat’s whisker. Fearing has been forced to manufacture many of the other minute components of his fly in the same way, using a micromachining laser and a rapid prototyping system that allows him to design his minuscule parts in a computer, automatically cut and cure them overnight, and assemble them by hand the next day under a microscope.</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>D</strong>     </span><span style="font-size: 12pt;">With the micro laser he cuts the fly’s wings out of a two-micron polyester sheet so delicate that it crumples if you breathe on it and must be reinforced with carbon-fiber spars. The wings on his current model flap at 275 times per second – faster than the insect’s own wings – and make the blowfly’s signature buzz. “Carbon fiber outperforms fly chitin,” he said, with a trace of self-satisfaction. He pointed out a protective plastic box on the lab bench, which contained the fly-bot itself, a delicate, origami-like framework of black carbon-fiber struts and hairlike wires that, not surprisingly, looks nothing like a real fly. A month later it achieved liftoff in a controlled flight on a boom. Fearing expects the fly-bot to hover in two or three years, and eventually to bank and dive with flylike virtuosity.</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>E</strong>     </span><span style="font-size: 12pt;">Stanford University roboticist Mark Cutkosky designed a gecko-insured climber that he christened Stickybot. In reality, gecko feet aren’t sticky – they’re dry and smooth to the touch – and owe their remarkable adhesion to some two billion spatula-tipped filaments per square centimeter on their toe pads, each filament only a hundred nanometers thick. These filaments are so small, in fact, that they interact at the molecular level with the surface on which the gecko walks, tapping into the low-level van der Waals forces generated by molecules’ fleeting positive and negative charges, which pull any two adjacent objects together. To make the toe pads for Stickybot, Cutkosky and doctoral student Sangbae Kim, the robot’s lead designer, produced a urethane fabric with tiny bristles that end in 30-micrometer points. Though not as flexible or adherent as the gecko itself, they hold the 500-gram robot on a vertical surface.</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"> </span><br />
<span style="font-size: 12pt;"><strong>F</strong>     </span><span style="font-size: 12pt;">Cutkosky endowed his robot with seven-segmented toes that drag and release just like the lizard’s, and a gecko-like stride that snugs it to the wall. He also crafted Stickybot’s legs and feet with a process he calls shape deposition manufacturing (SDM), which combines a range of metals, polymers, and fabrics to create the same smooth gradation from stiff to flexible that is present in the lizard’s limbs and absent in most man-made materials. SDM also allows him to embed actuators, sensors, and other specialized structures that make Stickybot climb better. Then he noticed in a paper on gecko anatomy that the lizard had to branch tendons to distribute its weight evenly across the entire surface of its toes. Eureka. “When I saw that, I thought, wow, that’s great!” He subsequently embedded a branching polyester cloth “tendon” in his robot’s limbs to distribute its load in the same way.</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"> </span><br />
<span style="font-size: 12pt;"><strong>G</strong>     </span><span style="font-size: 12pt;">Stickybot now walks up vertical surfaces of glass, plastic, and glazed ceramic tile, though it will be some time before it can keep up with a gecko. For the moment it can walk only on smooth surfaces, at a mere four centimeters per second, a fraction of the speed of its biological role model. The dry adhesive on Stickybot’s toes isn’t self-cleaning like the lizard’s either, so it rapidly clogs with dirt. “There are a lot of things about the gecko that we simply had to ignore,” Cutkosky says. Still, a number of real-world applications are in the offing. The Department of Defense’s Defense Advanced Research Projects Agency (DARPA), which funds the project, has it in mind for surveillance: an automaton that could slink up a building and perch there for hours or days, monitoring the terrain below. Cutkosky hypothesizes a range of civilian uses. “I’m trying to get robots to go places where they’ve never gone before,” he told me. “I would like to see Stickybot have a real-world function, whether it’s a toy or another application. Sure, it would be great if it eventually has a lifesaving or humanitarian role…”</span></p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>H</strong>     </span><span style="font-size: 12pt;">For all the power of the biomimetics paradigm, and the brilliant people who practice it, bio-inspiration has led to surprisingly few mass-produced products and arguably only one household word – Velcro, which was invented in 1948 by Swiss chemist George de Mestral, by copying the way cockleburs clung to his dog’s coat. In addition to Cutkosky‘s lab, five other high-powered research teams are currently trying to mimic gecko adhesion, and so far none has come close to matching the lizard’s strong, directional, self-cleaning grip. Likewise, scientists have yet to meaningfully re-create the abalone nanostructure that accounts for the strength of its shell, and several well-funded biotech companies have gone bankrupt trying to make artificial spider silk.</span></p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('13d9b396-732d-4205-bc1f-b1b99d9f7ed1', 'd9049ff5-6a65-4ab3-bd54-8a813cd55e8c', 'Part 4', '<p>Complete the notes below.</p>', 0, NULL, NULL, 31);
INSERT INTO public.passages VALUES ('e204614c-0476-4f25-9ff9-bf6839e25159', 'eaf6e439-5fb1-4fb9-8754-85b8288f5779', 'Part 4', '<p>Complete the notes below.</p>', 0, NULL, NULL, 31);
INSERT INTO public.passages VALUES ('8f28f354-3d19-4cac-a974-b68fe7c138cd', '2c5ce456-2929-4a4f-91b3-3869673522c1', 'Passage 1', '<p><span style="font-size: 12pt;"><strong>Wood: a valuable resource in New Zealand’s economy</strong></span></p>
<p>During the settlement of New Zealand by European immigrants, natural timbers played a major role. Wood was easily accessible and relatively cheap. A tradition of wooden houses arose, supported by the recognition that they were less likely to collapse suddenly during earthquakes, a not infrequent event in this part of the world. But in addition to demand from the domestic market, there was also a demand for forest products from overseas.</p>
<p>Early explorers recognised the suitability of the tall, straight trunks of the kauri for constructing sailing vessels. The kauri is a species of coniferous tree found only in small areas of the southern hemisphere. So from the early 1800s, huge amounts of this type of wood were sold to Australia and the UK for that purpose. For a period, the forestry industry was the country’s major export earner, but the rate of harvest was unsustainable and, by the beginning of the 20th century, indigenous timber exports were rapidly declining.</p>
<p>From the 1940s, newly established plantations of an imported species of tree called radiata pine supplied timber and other wood products in increasing quantities. By the 1960s, plantation-grown timber was providing most of the country’s sawn timber needs, especially for construction. Today, less than two per cent of timber is cut from indigenous forests, and almost all of that is used for higher-value end uses, such as furniture and fittings.</p>
<p>As the pine industry developed, it became apparent that this type of wood was also well suited for many uses. It makes excellent pulp, and is frequently used for posts, poles, furnishings and mouldings, particleboard, fibreboard, and for plywood and ‘engineered’ wood products. Pine by-products are used in the chemical and pharmaceutical industries and residues are consumed for fuel. This amazing versatility has encouraged the development of an integrated forest-products industry which is almost unique in the world.</p>
<p>Exporters of wood products have largely targeted the rapidly growing markets of South and East Asia and Australia. Eighty per cent of exports by value go to only five markets: Japan, Korea, China, the United States and Australia. The product mix remains heavily based on raw materials, with logs, sawn wood, pulp and paper comprising 75 per cent of export value. However, finished wood products such as panels and furniture components are exported to more than 50 countries.</p>
<p>In New Zealand itself, the construction industry is the principal user of solid wood products, servicing around 20,000 new house starts annually. However, the small size of New Zealand’s population (just over four million), plus its small manufacturing and remanufacturing base, limit the forestry industry’s domestic opportunities. For the last few years, local wood consumption has been around only four million cubic metres. Accordingly, the development of the export market is the key to the industry’s growth and contribution to the national economy in decades to come.</p>
<p>In 2004, forestry export receipts were about 11 per cent of the country’s total export income, their value having increased steadily for ten years, until affected by the exchange rate fluctuations and shipping costs of recent years. The forestry industry is New Zealand’s third largest export sector, generating around $3.3 billion annually from logs and processed wood products. But it is generally agreed that it is operating well below its capacity and, with the domestic market already at its peak, almost all of the extra wood produced in future will have to be marketed overseas. That presents a major marketing challenge for the industry.</p>
<p>Although the export of logs will continue to provide valuable earnings for forest owners, there is broad acceptance that the industry must be based on value-added products in future. So the industry is investigating various processing, infrastructure and investment strategies with a view to increasing the level of local manufacturing before export. The keys to success include better international marketing, product innovation, internationally competitive processing, better infrastructure, and a suitable political, regulatory and investment environment. The industry claims that given the right conditions, by 2025 the forestry sector could be the country’s biggest export earner, generating $20 billion a year and employing 60,000 people.</p>
<p>One competitive advantage that New Zealand has is its ability to source large quantities of softwood from renewable forests. Consumers in several key wood markets are becoming more worried about sustainability, and the industry is supporting the development of national standards as well as the recognition of these internationally. However, New Zealand is not the only country with a plantation-style forestry industry. Chile, Brazil, Argentina, South Africa and Australia all have extensive plantings of fast-growing species (hardwood and softwood), and in the northern hemisphere, Scandinavian countries have all expanded their forests or controlled their use in the interests of future production.</p>
<p>Finally, in addition to competition from other wood producers, New Zealand faces competition from goods such as wood substitutes. These include steel framing for houses. This further underlines the necessity for globally competitive production and marketing strategies.</p>
<p><em><strong>Pulp</strong>: wood which is crushed until soft enough to form the basis of paper.</em></p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('a3a37e43-58a0-4926-8fea-b8360816b266', '461ef05c-0221-4b58-96fb-d68e0acb0bc4', 'PASSAGE 1', '<p><span style="font-size: 12pt;"><strong>The history of the bar code</strong></span></p>
<p><strong>A</strong>     The first step toward today’s bar codes came in 1948, when Bernard Silver, a graduate student in the USA, overheard a conversation in the halls of Philadelphia’s Drexel Institute of Technology. The president of a food chain was pleading with a professor to undertake research on a method of capturing product information automatically at store checkouts. The professor turned down the request, but Bernard Silver mentioned the conversation to his friend Norman Woodland, a twenty-seven-year-old teacher at Drexel.</p>
<p><strong>B</strong>     The problem fascinated the two friends, and they set about thinking of a solution. Their first idea was to use patterns printed with an ink that would glow under ultraviolet light, and they built a device to test the concept. It worked, but the printing costs were high and the patterns faded over time. Nonetheless, they were convinced they had a workable idea. After several months of work they came up with the linear bar code, using elements from two established technologies: Morse code, in which letters and numbers are coded into a system of dots and dashes, and the method used to record soundtracks in movies. Silver and Woodland patented the idea in 1952, describing their invention as ‘article classification… through the medium of identifying patterns’. But the cost, together with the fact that their scanning equipment was rather unreliable, made the idea a non-starter at that time.</p>
<p><strong>C</strong>     Scanning systems made little progress until the 1970s, when lasers became affordable. Following this, various systems came into use around the world in stores, libraries, factories, and the like, each with its own proprietary code, but there was no standardization. A consortium of grocery manufacturers and retailers therefore set up a committee to look into bar codes, and to standardize what became known formally as the Universal Product Code (UPC). At the heart of the committee’s guidelines were a few basic principles. To make life easier for the cashier, bar codes would have to be readable from almost any angle and at a range of distances. Because they would be reproduced by the million, the labels would have to be cheap and easy to print. And to be affordable, automated checkout systems would have to pay for themselves in two and a half years.</p>
<p><strong>D</strong>     The committee considered more than a dozen versions of bar codes, including one based on multi-colored dots and another using a circular bull’s eye design with lines radiating from a central point. On April 1, 1973, they unanimously agreed on a standardized UPC, a combination of black and white lines and numbers, based on Woodland and Silver’s idea but developed by George Laurer at IBM. Alan Haberman, who headed the subcommittee as president of First National Stores, described the bar code as a kind of world language that worked for everyone. He recalls proudly. ‘We showed that it could be done on a massive scale, that cooperation… was possible for the common good, and that business didn’t need the government to shove them in the right direction.’</p>
<p><strong>E</strong>     The investment involved in the bar-code revolution was huge. Each of the tens of thousands of grocery outlets in the US had to spend at least $200,000 on new scanning equipment. Chains had to install new data processing centers and retrain their employees. Printers had to develop the new types of ink, plates, and other technology to reproduce the code with the exact tolerances it requires, and manufacturers had to spend millions of dollars a year on the labels.</p>
<p><strong>F</strong>     On June 26,1974, all the tests were done, all the proposals were complete, all the standards were set, and at a supermarket in Ohio, a single pack of Juicy Fruit chewing gum became the first retail product sold with the help of a bar-code scanner. Decades of schemes and billions of dollars in investment now became a practical reality. The bar code on any product could be read and understood in every suitably equipped store.</p>
<p><strong>G</strong>     The advantages of the system were not clear immediately, as wholesalers, retailers and customers remained suspicious. Some customers believed bar codes were a form of surveillance. During the early weeks Business Week magazine ran the headline ‘The Supermarket Scanner That Failed’. However, the benefits eventually became apparent. ‘It turns out there were massive savings in labor and other areas,’ Haberman says. These included checking out items at twice the speed compared to using traditional equipment, which meant shorter lines. And it did not take supermarkets too long to see that, as well as vastly improving customer service, the bar code could hugely reduce the amount of time spent checking inventory.</p>
<p><strong>H</strong>     Now, every day more than 5 billion bar codes are scanned in retail outlets throughout the world. Passengers’ luggage is tagged with bar codes by airlines. Staff attach them to babies to ensure the right babies go home from hospitals with the right mothers. Runners in major marathons set off with bar codes on their vests, and librarians rely on them. Tiny bar codes have even been mounted on bees by researchers to track their movements.</p>
<p><strong>I</strong>     As for that original pack of Juicy Fruit, it is now, unchewed and unopened, in the Smithsonian Institution National Museum of American History in Washington.</p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('1a17c47a-6a8d-4aef-aa6d-f45bb3014b3f', '461e652d-660a-4eec-9f14-19847df03789', 'PASSAGE 2', '<p data-path-to-node="4"><span class="citation-8522 citation-8523 citation-end-8523"><span style="font-size: 14pt;"><strong>The pirates of the ancient Mediterranean</strong></span><sup class="superscript" data-turn-source-index="5"><!----></sup></span><span class="citation-8522 citation-end-8522"><sup class="superscript" data-turn-source-index="6"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-83" data-path-to-node="5"><em data-path-to-node="5" data-index-in-node="0"><span class="citation-8518 citation-8519 citation-8520 citation-8521 citation-end-8521">In the first and second millennia BCE, pirates sailed around the<sup class="superscript" data-turn-source-index="7"><!----></sup></span><span class="citation-8518 citation-8519 citation-8520 citation-end-8520"> Mediterranean, attacking ships and avoiding<sup class="superscript" data-turn-source-index="8"><!----></sup></span><span class="citation-8518 citation-8519 citation-end-8519"> pursuers<sup class="superscript" data-turn-source-index="9"><!----></sup></span><span class="citation-8518 citation-end-8518"><sup class="superscript" data-turn-source-index="10"><!----></sup></span></em></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-84" data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0"><span class="citation-8516 citation-8517 citation-end-8517">A</span></strong></p>
<p data-path-to-node="6"><span class="citation-8514 citation-8515">When one mentions pirates, an image springs to most </span><span class="citation-8512 citation-8513 citation-8514 citation-8515 citation-end-8515">people’s minds of a crew of misfits, dar<sup class="superscript" data-turn-source-index="13"><!----></sup></span><span class="citation-8512 citation-8513 citation-8514 citation-end-8514">edevils and adventu<sup class="superscript" data-turn-source-index="14"><!----></sup></span><span class="citation-8512 citation-8513">rers in command of a tall sailing ship in the Caribbean Sea. </span><span class="citation-8505 citation-8506 citation-8507 citation-8508 citation-8509 citation-8510 citation-8511 citation-8512 citation-8513 citation-end-8513">Yet from the first to the third millennium BCE, thousands of years before these swashbucklers b<sup class="superscript" data-turn-source-index="15"><!----></sup></span><span class="citation-8505 citation-8506 citation-8507 citation-8508 citation-8509 citation-8510 citation-8511 citation-8512 citation-end-8512">egan spreading fear ac<sup class="superscript" data-turn-source-index="16"><!----></sup></span><span class="citation-8505 citation-8506 citation-8507 citation-8508 citation-8509 citation-8510 citation-8511 citation-end-8511">ross the Caribbean, pirates prowled the Mediterranean, raiding merchant ships and threatening vital trade routes. However, despit<sup class="superscript" data-turn-source-index="17"><!----></sup></span><span class="citation-8505 citation-8506 citation-8507 citation-8508 citation-8509 citation-8510 citation-end-8510">e all efforts and the might of various ancient states, piracy could not be stopped. The situation remained unchanged for thousands of years. Only when the pirates directly threatened the interests of ancient R<sup class="superscript" data-turn-source-index="18"><!----></sup></span><span class="citation-8505 citation-8506 citation-8507 citation-8508 citation-8509 citation-end-8509">ome did the Roman Republic organise a massive fleet to eliminate piracy. Under the command of the Roman general Pompey, Rome eradicated piracy, transforming the Mediterranean into ‘Mare Nos<sup class="superscript" data-turn-source-index="19"><!----></sup></span><span class="citation-8505 citation-8506 citation-8507 citation-8508 citation-end-8508">trum’ (Our Sea).<sup class="superscript" data-turn-source-index="20"><!----></sup></span><span class="citation-8505 citation-8506 citation-8507 citation-end-8507"><sup class="superscript" data-turn-source-index="21"><!----></sup></span><span class="citation-8505 citation-8506 citation-end-8506"><sup class="superscript" data-turn-source-index="22"><!----></sup></span><span class="citation-8505 citation-end-8505"><sup class="superscript" data-turn-source-index="23"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-85" data-path-to-node="7"><strong data-path-to-node="7" data-index-in-node="0"><span class="citation-8501 citation-8502 citation-8503 citation-8504 citation-end-8504">B<sup class="superscript" data-turn-source-index="24"><!----></sup></span><span class="citation-8501 citation-8502 citation-8503 citation-end-8503"><sup class="superscript" data-turn-source-index="25"><!----></sup></span><span class="citation-8501 citation-8502 citation-end-8502"><sup class="superscript" data-turn-source-index="26"><!----></sup></span><span class="citation-8501 citation-end-8501"><sup class="superscript" data-turn-source-index="27"><!----></sup></span></strong></p>
<p data-path-to-node="7"><span class="citation-8497 citation-8498 citation-8499 citation-8500 citation-end-8500">Although piracy in the Mediterranean is first recorded in ancient Egypt during the reign of Pharaoh Amenhotep III (c 1390<sup class="superscript" data-turn-source-index="28"><!----></sup></span><span class="citation-8497 citation-8498 citation-8499 citation-end-8499">–1353 BCE), it is reasonable to assume it predated this powerful civilisation. This is partly due to the great importance the Mediterranean held at this time, and partly due<sup class="superscript" data-turn-source-index="29"><!----></sup></span><span class="citation-8497 citation-8498 citation-end-8498"> to its geography. While the Mediterranean region is predominantly fertile, some parts are rugged and hilly, even mountainous. In the ancient times, the inhabitants of these areas relied heavily on marine<sup class="superscript" data-turn-source-index="30"><!----></sup></span><span class="citation-8497"> resources, including fish and salt. Most had </span><span class="citation-8496 citation-8497 citation-end-8497">their own boats, possessed good seafaring skills, and unsurpassed knowledge of the local coastline and sailing routes. <sup class="superscript" data-turn-source-index="31"><!----></sup></span><span class="citation-8493 citation-8494 citation-8495 citation-8496 citation-end-8496">Thus, it is not surprising that during hardships, these men turned to piracy. Geography itself further benefited the<sup class="superscript" data-turn-source-index="32"><!----></sup></span><span class="citation-8493 citation-8494 citation-8495 citation-end-8495"> pirates, with the numerous coves along the coast providing places for them to hide their boats and strike u<sup class="superscript" data-turn-source-index="33"><!----></sup></span><span class="citation-8493 citation-8494">ndetected. Before the invention of ocean-going caravels in the 15th century, ships could not easily cross long distances over open </span><span class="citation-8491 citation-8492 citation-8493 citation-8494 citation-end-8494">water. Thus, in the ancient world<sup class="superscript" data-turn-source-index="34"><!----></sup></span><span class="citation-8491 citation-8492 citation-8493 citation-end-8493"> most were restricted to a few well-known navigable routes that followed the coastli<sup class="superscript" data-turn-source-index="35"><!----></sup></span><span class="citation-8491 citation-8492">ne. </span><span class="citation-8488 citation-8489 citation-8490 citation-8491 citation-8492 citation-end-8492">Caught in a trap, a slow merchant ship laden with goods had no other option but to sur<sup class="superscript" data-turn-source-index="36"><!----></sup></span><span class="citation-8488 citation-8489 citation-8490 citation-8491 citation-end-8491">render. In addition, knowle<sup class="superscript" data-turn-source-index="37"><!----></sup></span><span class="citation-8488 citation-8489 citation-8490 citation-end-8490">dge of the local area helped the pirates to avoid retaliation once a state fleet arrived.<sup class="superscript" data-turn-source-index="38"><!----></sup></span><span class="citation-8488 citation-8489 citation-end-8489"><sup class="superscript" data-turn-source-index="39"><!----></sup></span><span class="citation-8488 citation-end-8488"><sup class="superscript" data-turn-source-index="40"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-86" data-path-to-node="8"><strong data-path-to-node="8" data-index-in-node="0"><span class="citation-8485 citation-8486 citation-8487 citation-end-8487">C<sup class="superscript" data-turn-source-index="41"><!----></sup></span><span class="citation-8485 citation-8486 citation-end-8486"><sup class="superscript" data-turn-source-index="42"><!----></sup></span><span class="citation-8485 citation-end-8485"><sup class="superscript" data-turn-source-index="43"><!----></sup></span></strong> </p>
<p data-path-to-node="8"><span class="citation-8482 citation-8483 citation-8484 citation-end-8484">One should also add that it was not unknown in<sup class="superscript" data-turn-source-index="44"><!----></sup></span><span class="citation-8482 citation-8483"> the first and second millennia BCE for governments to resort to pirates’ services, especially during wartime, employing their skills and </span><span class="citation-8481 citation-8482 citation-8483 citation-end-8483">numbers against their opponents. A pirate fleet would serve in the f<sup class="superscript" data-turn-source-index="45"><!----></sup></span><span class="citation-8481 citation-8482 citation-end-8482">irst wave of attack, preparing the way for the nav<sup class="superscript" data-turn-source-index="46"><!----></sup></span><span class="citation-8481">y. </span><span class="citation-8476 citation-8477 citation-8478 citation-8479 citation-8480 citation-8481 citation-end-8481">Some of the regions were known for providing safe harbours to pirates, who, in return, boosted the local econo<sup class="superscript" data-turn-source-index="47"><!----></sup></span><span class="citation-8476 citation-8477 citation-8478 citation-8479 citation-8480 citation-end-8480">my.<sup class="superscript" data-turn-source-index="48"><!----></sup></span><span class="citation-8476 citation-8477 citation-8478 citation-8479 citation-end-8479"><sup class="superscript" data-turn-source-index="49"><!----></sup></span><span class="citation-8476 citation-8477 citation-8478 citation-end-8478"><sup class="superscript" data-turn-source-index="50"><!----></sup></span><span class="citation-8476 citation-8477 citation-end-8477"><sup class="superscript" data-turn-source-index="51"><!----></sup></span><span class="citation-8476 citation-end-8476"><sup class="superscript" data-turn-source-index="52"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-87" data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0"><span class="citation-8471 citation-8472 citation-8473 citation-8474 citation-8475 citation-end-8475">D<sup class="superscript" data-turn-source-index="53"><!----></sup></span><span class="citation-8471 citation-8472 citation-8473 citation-8474 citation-end-8474"><sup class="superscript" data-turn-source-index="54"><!----></sup></span><span class="citation-8471 citation-8472 citation-8473 citation-end-8473"><sup class="superscript" data-turn-source-index="55"><!----></sup></span><span class="citation-8471 citation-8472 citation-end-8472"><sup class="superscript" data-turn-source-index="56"><!----></sup></span><span class="citation-8471 citation-end-8471"><sup class="superscript" data-turn-source-index="57"><!----></sup></span></strong></p>
<p data-path-to-node="9"><span class="citation-8466 citation-8467 citation-8468 citation-8469 citation-8470 citation-end-8470">The first known record of a named group of Mediterranean pirates, made during the rule of ancient Egyptian Pharaoh Akhenaten (c 1353<sup class="superscript" data-turn-source-index="58"><!----></sup></span><span class="citation-8466 citation-8467 citation-8468 citation-8469 citation-end-8469">–1336 BCE), was in the Amarna Letters. These were extracts of diplomatic correspondence between the pharaoh and his allies, and covered many pressing issues, including piracy. It seems <sup class="superscript" data-turn-source-index="59"><!----></sup></span><span class="citation-8466 citation-8467 citation-8468 citation-end-8468">the pharaoh was troubled by two distinct pirate groups, the Lukka and the Sherden. Despite the Egyptian fleet’s best efforts, the pirates continued to cause substantial disruption to regio<sup class="superscript" data-turn-source-index="60"><!----></sup></span><span class="citation-8466 citation-8467">nal commerce. In the letters, the </span><span class="citation-8465 citation-8466 citation-8467 citation-end-8467">king of Alashiya (modern Cyprus) rejected Akhenaten’s claims of a connection with the Lukka (ba<sup class="superscript" data-turn-source-index="61"><!----></sup></span><span class="citation-8465 citation-8466 citation-end-8466">sed in modern-day Turkey<sup class="superscript" data-turn-source-index="62"><!----></sup></span><span class="citation-8465">). </span><span class="citation-8463 citation-8464 citation-8465 citation-end-8465">The king assured Akhenaten he was prepared to punish any of his subjects involved in piracy.<sup class="superscript" data-turn-source-index="63"><!----></sup></span><span class="citation-8463 citation-8464 citation-end-8464"><sup class="superscript" data-turn-source-index="64"><!----></sup></span><span class="citation-8463 citation-end-8463"><sup class="superscript" data-turn-source-index="65"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-88" data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0"><span class="citation-8460 citation-8461 citation-8462 citation-end-8462">E<sup class="superscript" data-turn-source-index="66"><!----></sup></span><span class="citation-8460 citation-8461 citation-end-8461"><sup class="superscript" data-turn-source-index="67"><!----></sup></span><span class="citation-8460 citation-end-8460"><sup class="superscript" data-turn-source-index="68"><!----></sup></span></strong></p>
<p data-path-to-node="10"><span class="citation-8457 citation-8458 citation-8459 citation-end-8459">The ancient Greek w<sup class="superscript" data-turn-source-index="69"><!----></sup></span><span class="citation-8457 citation-8458">orld’s experience of piracy was different from that of Egyptian rulers. While Egypt’s power was land-based, the ancient </span><span class="citation-8456 citation-8457 citation-8458 citation-end-8458">Greeks relied on the Mediterranean in almost all aspects of life, from tra<sup class="superscript" data-turn-source-index="70"><!----></sup></span><span class="citation-8456 citation-8457 citation-end-8457">de to warfare. Interestingly, in his work<sup class="superscript" data-turn-source-index="71"><!----></sup></span><span class="citation-8456">s the </span><em data-path-to-node="10" data-index-in-node="262"><span class="citation-8456">Iliad</span></em> <span class="citation-8453 citation-8454 citation-8455 citation-8456">and the </span><em data-path-to-node="10" data-index-in-node="276"><span class="citation-8453 citation-8454 citation-8455 citation-8456">Odyssey</span></em><span class="citation-8453 citation-8454 citation-8455 citation-8456 citation-end-8456">, the ancient Greek writer Homer not only condones, but praises the lifestyle and actions of pirates. <sup class="superscript" data-turn-source-index="72"><!----></sup></span><span class="citation-8453 citation-8454 citation-8455 citation-end-8455">The opinion remained unchanged in the following centuries. The ancient Greek historian Thucydides, for instance, glorified pirates’ daring attacks on ships or eve<sup class="superscript" data-turn-source-index="73"><!----></sup></span><span class="citation-8453 citation-8454 citation-end-8454">n cities. For Greeks, piracy was a part of everyday life. Even high-ranking members of the state were not beyond engaging in such activities. According to the Greek orator De<sup class="superscript" data-turn-source-index="74"><!----></sup></span><span class="citation-8453">mosthenes, in 355 BCE, Athenian ambassadors made a </span><span class="citation-8452 citation-8453 citation-end-8453">detour from their official travel to capture a ship sailing from Egypt, taking the wealth found onboard for themselves! <sup class="superscript" data-turn-source-index="75"><!----></sup></span><span class="citation-8450 citation-8451 citation-8452 citation-end-8452">The Greeks’ liberal approach towards piracy does not mean they always tolerated it, but attempts to curtail pir<sup class="superscript" data-turn-source-index="76"><!----></sup></span><span class="citation-8450 citation-8451 citation-end-8451">acy were hampered by the large number of pirates operating in the Mediterranean.<sup class="superscript" data-turn-source-index="77"><!----></sup></span><span class="citation-8450 citation-end-8450"><sup class="superscript" data-turn-source-index="78"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-89" data-path-to-node="11"><strong data-path-to-node="11" data-index-in-node="0"><span class="citation-8448 citation-8449 citation-end-8449">F<sup class="superscript" data-turn-source-index="79"><!----></sup></span><span class="citation-8448 citation-end-8448"><sup class="superscript" data-turn-source-index="80"><!----></sup></span></strong></p>
<p data-path-to-node="11"><span class="citation-8446 citation-8447 citation-end-8447">The rising power of ancient Rome required the Roman Republic to deal with piracy in the Mediterranean. While piracy was a serious issue for the Republic, Rome profited greatly from its existence. P<sup class="superscript" data-turn-source-index="81"><!----></sup></span><span class="citation-8446">irate raids provided a steady source of slaves, essential for Rome’s agriculture and mining </span><span class="citation-8444 citation-8445 citation-8446 citation-end-8446">industries. But this arrangement could work only while the pirates left Roman interests alone. Pirate attacks on gr<sup class="superscript" data-turn-source-index="82"><!----></sup></span><span class="citation-8444 citation-8445">ain ships, which were essential to Roman citizens, led to angry voices in the Senate, demanding punishment of the culprits. Rome, however, did nothing, further encouraging </span><span class="citation-8443 citation-8444 citation-8445 citation-end-8445">piracy. By t<sup class="superscript" data-turn-source-index="83"><!----></sup></span><span class="citation-8443 citation-8444 citation-end-8444">he 1st century BCE, emboldened pirates<sup class="superscript" data-turn-source-index="84"><!----></sup></span><span class="citation-8443"> kidnapped prominent Roman dignitaries, asking for a large ransom </span><span class="citation-8440 citation-8441 citation-8442 citation-8443 citation-end-8443">to be paid. Their most famous hostage was none other than Julius Caesar, captured in 75 BCE.<sup class="superscript" data-turn-source-index="85"><!----></sup></span><span class="citation-8440 citation-8441 citation-8442 citation-end-8442"><sup class="superscript" data-turn-source-index="86"><!----></sup></span><span class="citation-8440 citation-8441 citation-end-8441"><sup class="superscript" data-turn-source-index="87"><!----></sup></span><span class="citation-8440 citation-end-8440"><sup class="superscript" data-turn-source-index="88"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_460b7dd70e7dc346-90" data-path-to-node="12"><strong data-path-to-node="12" data-index-in-node="0"><span class="citation-8436 citation-8437 citation-8438 citation-8439 citation-end-8439">G<sup class="superscript" data-turn-source-index="89"><!----></sup></span><span class="citation-8436 citation-8437 citation-8438 citation-end-8438"><sup class="superscript" data-turn-source-index="90"><!----></sup></span><span class="citation-8436 citation-8437 citation-end-8437"><sup class="superscript" data-turn-source-index="91"><!----></sup></span><span class="citation-8436 citation-end-8436"><sup class="superscript" data-turn-source-index="92"><!----></sup></span></strong></p>
<p data-path-to-node="12"><span class="citation-8432 citation-8433 citation-8434 citation-8435 citation-end-8435">By now, Rome was well <sup class="superscript" data-turn-source-index="93"><!----></sup></span><span class="citation-8432 citation-8433 citation-8434 citation-end-8434">aware that pirates had outlived their usefulness. The time had come for concerted action. In<sup class="superscript" data-turn-source-index="94"><!----></sup></span><span class="citation-8432 citation-8433 citation-end-8433"> 67 BCE, a new law granted Pompey vast funds to combat the Mediterranean menace. Taking personal command, Pompey divided the entire Mediterranean into 13 districts, assigning a fleet<sup class="superscript" data-turn-source-index="95"><!----></sup></span><span class="citation-8432"> and commander to each. After cleansing one district of pirates, the </span><span class="citation-8431 citation-8432 citation-end-8432">fleet would join another in the next district. The process continued until the entire Mediterranean was free of pirat<sup class="superscript" data-turn-source-index="96"><!----></sup></span><span class="citation-8431">es. </span><span class="citation-8430 citation-8431 citation-end-8431">Although thousands of pirates died at the hands of Pompey’s troops, as a long-term solution to the problem, many m<sup class="superscript" data-turn-source-index="97"><!----></sup></span><span class="citation-8430 citation-end-8430">ore were offered land in fertile areas located far from the sea. Instead of a maritime menace, Rome got productive farmers that further boosted its economy.<sup class="superscript" data-turn-source-index="98"><!----></sup></span></p>', 1, NULL, NULL, 14);
INSERT INTO public.passages VALUES ('2ac39a82-8548-49a3-a405-ed889bf37225', 'c8e8efca-a3f8-4ff7-9377-11487eb7a4b1', 'Part 4', '', 0, NULL, NULL, 31);
INSERT INTO public.passages VALUES ('bbf91301-5bb1-4a15-8465-c0a0f209930a', '461e652d-660a-4eec-9f14-19847df03789', 'PASSAGE 3', '<p data-path-to-node="4"><strong data-path-to-node="4" data-index-in-node="0"><span class="citation-12030 citation-12031 citation-end-12031"><span style="font-size: 14pt;">The persistence and peril of misinformation</span><sup class="superscript" data-turn-source-index="5"><!----></sup></span><span class="citation-12030 citation-end-12030"><sup class="superscript" data-turn-source-index="6"><!----></sup></span></strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-110" data-path-to-node="5"><em data-path-to-node="5" data-index-in-node="0"><span class="citation-12028 citation-12029 citation-end-12029">Brian Southwell looks at how human brains verify information and discusses s<sup class="superscript" data-turn-source-index="7"><!----></sup></span><span class="citation-12028 citation-end-12028">ome of the challenges of batt<sup class="superscript" data-turn-source-index="8"><!----></sup></span>ling widespread falsehoods</em></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-111" data-path-to-node="6"><span class="citation-12022 citation-12023 citation-12024 citation-12025 citation-12026 citation-12027 citation-end-12027">Misinformation – both deliberately promoted and accidentally shared – is perhaps an inevitable part of the world in which we live, but it is not a new problem. People likely have lied to one another for roughly as long as verbal communication has existed. Dece<sup class="superscript" data-turn-source-index="9"><!----></sup></span><span class="citation-12022 citation-12023 citation-12024 citation-12025 citation-12026 citation-end-12026">iving others can offer an apparent opportunity to gain strategic advanta<sup class="superscript" data-turn-source-index="10"><!----></sup></span><span class="citation-12022 citation-12023 citation-12024 citation-12025 citation-end-12025">ge, to motivate others to action, or even to protect interpersonal <sup class="superscript" data-turn-source-index="11"><!----></sup></span><span class="citation-12022 citation-12023 citation-12024 citation-end-12024">bonds. Moreover, people inadvertently have been sharing inaccurate information wit<sup class="superscript" data-turn-source-index="12"><!----></sup></span><span class="citation-12022 citation-12023 citation-end-12023">h one another for thousands of years.<sup class="superscript" data-turn-source-index="13"><!----></sup></span><span class="citation-12022 citation-end-12022"><sup class="superscript" data-turn-source-index="14"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-112" data-path-to-node="7"><span class="citation-12020 citation-12021 citation-end-12021">However, we currently live in an era in which technology enables information to reach large audiences distributed across the globe, and thus the potential for immediat<sup class="superscript" data-turn-source-index="15"><!----></sup></span><span class="citation-12020">e </span><span class="citation-12018 citation-12019 citation-12020 citation-end-12020">and widespread effects from misinformation now looms larger than in the past. Yet the means to correct misinfor<sup class="superscript" data-turn-source-index="16"><!----></sup></span><span class="citation-12018 citation-12019 citation-end-12019">mation might, over time, be found in those same patterns of mass communication and of the facilit<sup class="superscript" data-turn-source-index="17"><!----></sup></span><span class="citation-12018 citation-end-12018">ated spread of information.<sup class="superscript" data-turn-source-index="18"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-113" data-path-to-node="8"><span class="citation-12017">The main worry regarding misinformation is </span><span class="citation-12016 citation-12017 citation-end-12017">its potential to unduly influence attitudes and behavior, leading people to think and act differently than they would <sup class="superscript" data-turn-source-index="19"><!----></sup></span><span class="citation-12014 citation-12015 citation-12016 citation-end-12016">if they were correctly informed, as suggested by the research teams of Stephan Lewandowsky of the University of Bri<sup class="superscript" data-turn-source-index="20"><!----></sup></span><span class="citation-12014 citation-12015 citation-end-12015">stol and Elizabeth Marsh of Duke University, among others. In other words, we worry that misinformation mi<sup class="superscript" data-turn-source-index="21"><!----></sup></span><span class="citation-12014">ght lead people to hold misperceptions (</span><span class="citation-12013 citation-12014 citation-end-12014">or false beliefs) and that these misperceptions, especially when t<sup class="superscript" data-turn-source-index="22"><!----></sup></span><span class="citation-12013 citation-end-12013">hey occur among large groups of people, may have detrimental, downstream consequences for health, social harmony, and the political climate.<sup class="superscript" data-turn-source-index="23"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-114" data-path-to-node="9"><span class="citation-12012">At least three observations related to misinformation in the contemporary mass-media environment warrant the attention of researchers, policy makers, and really everyone who watches television, listens to the radio, or reads </span><span class="citation-12011 citation-12012 citation-end-12012">information online. First of all, people who encounter misinformation tend to believe it, at least initially. Secondly<sup class="superscript" data-turn-source-index="24"><!----></sup></span><span class="citation-12011">, electronic and print media often do not block </span><span class="citation-12010 citation-12011 citation-end-12011">many types of misinformation before it appears in content available to large audiences. Thirdly, countering misinfor<sup class="superscript" data-turn-source-index="25"><!----></sup></span><span class="citation-12010 citation-end-12010">mation once it has enjoyed wide exposure can be a resource-intensive effort.<sup class="superscript" data-turn-source-index="26"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-115" data-path-to-node="10"><span class="citation-12009">Knowing what happens when people initially </span><span class="citation-12008 citation-12009 citation-end-12009">encounter misinformation holds tremendous importance for estimating the potential for subsequent problems. Alth<sup class="superscript" data-turn-source-index="27"><!----></sup></span><span class="citation-12008">ough it is fairly routine for individuals to come across information that is false, the question of exactly how – and when – we mentally label information as true or false has garnered </span><span class="citation-12007 citation-12008 citation-end-12008">philosophical <sup class="superscript" data-turn-source-index="28"><!----></sup></span><span class="citation-12007">debate. The dilemma is neatly summarized by a contrast between how the 17th-century philosophers René Descartes and Baruch Spinoza described human information engagement, </span><span class="citation-12005 citation-12006 citation-12007 citation-end-12007">with conflicting predictions that only recently have been empirically tested in robust ways. Descartes argued <sup class="superscript" data-turn-source-index="29"><!----></sup></span><span class="citation-12005 citation-12006 citation-end-12006">that a person only accepts or rejects information after considering its truth or falsehood; Spinoza argued that people accept all encountered information (or misinformation) by default and then subsequently verify or reject it through<sup class="superscript" data-turn-source-index="30"><!----></sup></span><span class="citation-12005 citation-end-12005"> a sepa<sup class="superscript" data-turn-source-index="31"><!----></sup></span>rate cognitive <span class="citation-12003 citation-12004 citation-end-12004">process. In recent decades, empirical evidence from the research teams of Erik Asp of the University of Chicago and Daniel Gilbert at Harvard University, among others, has supported Spinoza’s account: people appear to encode all new information as if it were true, even if only momentarily, and later tag the information as being either tru<sup class="superscript" data-turn-source-index="32"><!----></sup></span><span class="citation-12003">e or false, a pattern that seems consistent with the observation that mental resources </span><span class="citation-12000 citation-12001 citation-12002 citation-12003 citation-end-12003">for skepticism physically reside in a different part of the brain than the resources used in perceiving and en<sup class="superscript" data-turn-source-index="33"><!----></sup></span><span class="citation-12000 citation-12001 citation-12002 citation-end-12002">coding.<sup class="superscript" data-turn-source-index="34"><!----></sup></span><span class="citation-12000 citation-12001 citation-end-12001"><sup class="superscript" data-turn-source-index="35"><!----></sup></span><span class="citation-12000 citation-end-12000"><sup class="superscript" data-turn-source-index="36"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-116" data-path-to-node="11"><span class="citation-11997 citation-11998 citation-11999 citation-end-11999">What about our second observation that misinformation often can appear in electronic or print media without being preemptively blocked? In support of this, one might consider the nature of regulatory structures in the Unit<sup class="superscript" data-turn-source-index="37"><!----></sup></span><span class="citation-11997 citation-11998">ed States: regulatory agencies here tend to focus on post hoc detection of broadcast information. Organizations such as </span><span class="citation-11995 citation-11996 citation-11997 citation-11998 citation-end-11998">the Food and Drug Administration (FDA) offer considerable monitoring and notification functions, but <sup class="superscript" data-turn-source-index="38"><!----></sup></span><span class="citation-11995 citation-11996 citation-11997 citation-end-11997">these roles typical<sup class="superscript" data-turn-source-index="39"><!----></sup></span><span class="citation-11995 citation-11996 citation-end-11996">ly do not involve preemptive censoring. The FDA oversees direct-to-consumer prescription drug advertising, for example, and has developed mechanisms such as the ‘Bad Ad’ pr<sup class="superscript" data-turn-source-index="40"><!----></sup></span><span class="citation-11995">ogram, through which people can report advertising in apparent violation </span><span class="citation-11994 citation-11995 citation-end-11995">of FDA guidelines on drug risks. <sup class="superscript" data-turn-source-index="41"><!----></sup></span><span class="citation-11994">Such programs, although laudable and useful, do not keep false advertising off the airwaves. </span><span class="citation-11993 citation-11994 citation-end-11994">In addition, even misinformation that is successfully corrected can continue to affect attitudes.<sup class="superscript" data-turn-source-index="42"><!----></sup></span><span class="citation-11993 citation-end-11993"><sup class="superscript" data-turn-source-index="43"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-117" data-path-to-node="12"><span class="citation-11991 citation-11992 citation-end-11992">This leads us t<sup class="superscript" data-turn-source-index="44"><!----></sup></span><span class="citation-11991">o our third observation: a campaign to correct misinformation, even </span><span class="citation-11987 citation-11988 citation-11989 citation-11990 citation-11991 citation-end-11991">if rhetorically compelling, requires resources and planning to acco<sup class="superscript" data-turn-source-index="45"><!----></sup></span><span class="citation-11987 citation-11988 citation-11989 citation-11990 citation-end-11990">mplish necessary reach and frequency. For corrective campaigns to be persuasive, audiences need to be able to comprehend them, which requires either effort to frame messages i<sup class="superscript" data-turn-source-index="46"><!----></sup></span><span class="citation-11987 citation-11988 citation-11989 citation-end-11989">n ways that are accessible or effort to educate and sensitize audiences to the possibility of misinformation. That some audiences might be unaware of the potential for misinformation also suggests the utility of med<sup class="superscript" data-turn-source-index="47"><!----></sup></span><span class="citation-11987 citation-11988 citation-end-11988">ia literacy efforts as early as elementary school. Even with journalists and scholars pointing to the phenomenon of ‘fake news’, people do not distinguish between demonstrably false stories and those based in fact when<sup class="superscript" data-turn-source-index="48"><!----></sup></span><span class="citation-11987"> scanning and processing written </span><span class="citation-11986 citation-11987 citation-end-11987">information.<sup class="superscript" data-turn-source-index="49"><!----></sup></span><span class="citation-11986 citation-end-11986"><sup class="superscript" data-turn-source-index="50"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_88119913dca8a5f9-118" data-path-to-node="13"><span class="citation-11984 citation-11985">We live at a time when widespread misinformation is common. Yet at this time many people </span><span class="citation-11983 citation-11984 citation-11985 citation-end-11985">also are pas<sup class="superscript" data-turn-source-index="51"><!----></sup></span><span class="citation-11983 citation-11984 citation-end-11984">sionately developing potential solutions and remedies. The journey forward undoubtedly will be a long <sup class="superscript" data-turn-source-index="52"><!----></sup></span><span class="citation-11983">and arduous one. Future remedies will require not </span><span class="citation-11981 citation-11982 citation-11983 citation-end-11983">only continued theoretical consideration but also the development and maintenance o<sup class="superscript" data-turn-source-index="53"><!----></sup></span><span class="citation-11981 citation-11982 citation-end-11982">f consistent monitoring tools – and a recognition among fellow members of society that claims which find prominence in the media that are insufficiently based in scientific consensus and social reality should be countered. Misinformation arises as a result of<sup class="superscript" data-turn-source-index="54"><!----></sup></span><span class="citation-11981 citation-end-11981"> human fallibility and human information needs. To overcome the worst effects of the phenomenon, we will need coordinate<sup class="superscript" data-turn-source-index="55"><!----></sup></span>d efforts over time, rather than any singular one-time panacea we could hope to offer.</p>', 2, NULL, NULL, 27);
