INSERT INTO public.passages VALUES ('1cbf83c7-7ff5-4ce8-ac95-a9d34575ab0e', '057814c5-9ba0-4b41-950d-ec52933dcd2b', 'Part 2', '', 1, 441, 819, 11);
INSERT INTO public.passages VALUES ('5d546afa-600e-4da2-a724-e9db3583616a', '4e0c8180-428c-4c81-8de5-85613e8dea80', 'Passage 1', '<p><span style="font-size: 12pt;"><strong>Investing in the Future</strong></span></p>
<p>History has shown the value of giving money to the University of Auckland</p>
<p>The founding and development of many universities has been dependent on philanthropy. This has been true from some of the oldest universities such as Bologna, Oxford and Cambridge in the twelfth century, to relative newcomers like the universities of Harvard and Yale in the seventeenth century. Wealthy merchants gave young institutions money, land, libraries and rare items. Their belief in the value of higher learning is echoed by the growing number of philanthropists whose gifts have helped transform the University of Auckland, the largest university in New Zealand.</p>
<p>In 1884 Mr Justice Gillies made history when he gave $3,000 to the then very young University of Auckland, and so became its original philanthropist. Gillies’ gift was more generous even than those regularly given to New Zealand’s older University of Otago, and was exceptional because Auckland had a smaller population and was less wealthy than the other university cities at that time. However, from the 1930s privately funded prizes and scholarships began to be seen more frequently in Auckland. In that decade a local engineer and former lecturer in engineering, Samuel Crookes, launched a fund to save the engineering school in Auckland, which the state was determined to see discontinued, and raised over $6,500 in three years. Another significant philanthropist, Sir William Goodfellow, made his initial gift to the University in 1947 – $50,000 to build the Maclaurin Chapel. Since then, he and succeeding generations of the family have given numerous scholarships and fellowships and established a school within the University bearing the family’s name.</p>
<p>The University had a difficult decade in the 1950s as it was short of equipment, buildings and money. It also had its first taste of international rivalry, when universities in many parts of the world competed to attract first class lecturers. In Auckland the problem largely resulted from the fact that academic salaries had slipped well behind those available in Britain and Australia, so the strongest candidates tended to be recruited to those countries. But when the new Medical School opened in 1968, it attracted significant gifts for academic positions and equipment from an unusually wide range of donors, including individuals, trusts, charitable foundations, societies and community groups. It also became the permanent home of the Philson Library, which by then consisted of some 8,000 books.</p>
<p>The first of the modern public appeals for funds took place in the 1960s, when Alan Highet built the Student Union complex. This was followed by another appeal in 1983 under the then Chancellor Henry Cooper who raised $800,000 to celebrate the University’s centenary. These modern campaigns built on the successful campaigns of the past but included a number of new features. There was of course the familiar emphasis on donations from individuals, but the modern approach also stressed the importance of the University and business closer together and specifically seeking donations from that sector.</p>
<p>Building on this success, the current ‘Leading the Way’ campaign was launched. It is intended as a drive to secure support for the whole University, with a focus on generating funds to recruit, support and retain the very best staff for the University. The current campaign has raised the whole process of philanthropy to a new level, and changed expectations. The University is investing considerable time and energy in devising new methods of fund-raising both within its local communities – and remembering that New Zealanders love to travel – by looking at campaigns in other parts of the world, and targeting alumni, or former students now living overseas.</p>
<p>‘What it taught us,’ says John Taylor, Director of External Relations, ‘was that the campaign had to fit into the Strategic Plan of the University … As we kept talking we realised that we could have a transformative effect on the future of New Zealand by highlighting the potential benefits of high quality research.’ The example Taylor gives is the $4.5 million gift to establish an information centre at the University’s Marine Science laboratory on the coast at Leigh. He stresses that the fund-raising drive was so successful in part because the publicity used at the time highlighted the public benefit from the project.</p>
<p>On the financial side, the University’s Vice-Chancellor, Stuart McCutcheon, explains that a fault they found in their campaigns actually turned out to be a stroke of good fortune. ‘In the course of developing these new fund-raising systems,’ he says, ‘we have come to realise that there has been considerable giving to the University that has not been previously recorded through our Advancement Office … This has been in the order of $10 million per year over the campaign period.’ The good news from this error is that at the recent Chancellor’s dinner it was announced that the campaign target was now being increased from $100 million to $150 million, and would recognise all sources of philanthropic support. It’s a long way from Gillies’ first $3,000 gift.</p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('b1dda976-6c05-49e7-9bb7-6c84fb553004', '4e0c8180-428c-4c81-8de5-85613e8dea80', 'Passage 2', '<p><strong>Will Eating Less Make You Live Longer?</strong></p>
<p><em>The latest in a conflicting series of studies suggests calorie restriction could potentially slow ageing in humans</em></p>
<p><strong>A   </strong>   Calorie restriction, or ‘semi-starvation’ as some refer to it, has been proven to extend lifespan in many living organisms from yeast to mice, but the picture for primates, including humans, is not so clear. Research published by a team at the University of Wisconsin in the United States shows that rhesus monkeys also live longer on a calorie-restricted diet. But those findings disagree with research by the National Institute on Aging (NIA) in Maryland, also in the United States. Rozalyn Anderson, of the Wisconsin team, says the research is not intended as a recommendation of calorie restriction. ‘I find the idea monumentally unattractive!’ she says. ‘We study it because it is so effective at delaying ageing and the onset of age-related disease. It’s a way to tease out what it is that creates increased disease vulnerability as a function of age.’</p>
<p><strong>B    </strong>  Both groups started long-term trials on rhesus monkeys in the late 1980s to determine whether calorie restriction would extend the lifespan of primates. In mice, many experiments had come to the same finding: feed them a diet with 30% fewer calories and see a lifespan extension of 40%. The monkey trials were set up in a similar way: researchers took the calorie content of a standard monkey diet, cut it by 30% (while continuing to supply all essential nutrients) and monitored whether those monkeys lived longer, healthier lives than those on the standard diet.</p>
<p><strong>C    </strong>  In 2009, with the monkeys approaching old age, preliminary findings of the two trials started coming in. For the Wisconsin monkeys, calorie restriction seemed to be working. Compared to well-fed control animals, the lean monkeys were living longer and suffering less from the diseases of ageing: diabetes, heart disease and brain diseases. However, in 2012 the NIA results emerged with a dramatically different conclusion: their monkeys were not living any longer than the controls, although they were healthier.</p>
<p><strong>D    </strong>  The Wisconsin group’s latest results confirm that their calorie-restricted monkeys are living longer than the controls. They also offer a possible explanation of why the two groups’ findings don’t agree, and that lies in the treatment of the control group. The Wisconsin study began with monkeys in early adulthood. Initially, all the monkeys were allowed to eat as much as they liked. A few months into the trial, the monkeys were placed into one of two groups: the controls (who continued to be fed as much as they wished) and the calorie-restricted monkeys (who were given an individualised diet of 30% less than they were previously eating).</p>
<p><strong>E   </strong>   The NIA study differed in two ways. First, the control group of monkeys were not allowed to eat as much as they wished. They were given a diet considered to represent a normal calorie count, while the calorie-restricted monkeys were fed 30% less than that. Second, whereas the Wisconsin monkeys were given highly processed food high in sucrose, making it easy to standardise, the NIA diet was based on whole grains, fish oils, and was very low in sugar. These different settings for the normal control diet may provide an explanation of why the two groups showed different results.</p>
<p><strong>F   </strong>   The Wisconsin group may in effect have studied the effects of ‘overeating’. Their control animals weighed up to 10% more than average for their age and gender. Compared to them, the calorie-restricted animals not only suffered fewer diseases, they lived longer. Julie Mattison, head of the NIA study, observes that an overweight person who goes to a fast food restaurant every day will obviously benefit if their calories are cut back by 30%.</p>
<p><strong>G  </strong>   The NIA study fed their control monkeys what they considered a ‘standard’ caloric intake and saw that longevity for monkeys that were fed 30% less was the same. But in Anderson’s view, the NIA control monkeys were not fed enough; the NIA was calorie restricting both groups of animals. Their older female control monkeys, for example, weighed nearly 20% less than the national average. Indeed, Anderson points out that several of the NIA control monkeys have lived past the age of 40, far exceeding the 27- year average lifespan for captive rhesus monkeys. ‘That’s the maximum lifespan ever detected for the species, so the idea that their intervention is doing nothing is really at odds with the data,’ says Anderson.</p>
<p><strong>H  </strong>    However, neither group had the right notion of a standard diet according to Leonie Heilbronn, who researches calorie restriction and healthy ageing at the University of Adelaide in Australia. Heilbronn points out that the NIA controls were a very healthy set of monkeys and leaner than a control monkey should be. On the other hand, she notes, the Wisconsin controls were a little bigger than they had to be. On balance, Heilbronn agrees with the Wisconsin researcher’s argument. ‘I think these studies suggest calorie restriction definitely will increase lifespan,’ she says.</p>
<p><strong>I   </strong>   Both studies agree that cutting calories is beneficial to health — in both cases the calorie-restricted monkeys had fewer diseases related to ageing. As to the question of whether calorie restriction extends lifespan in primates, Anderson and Mattison are currently working together to compare the two studies’ raw data. They plan to co-publish a joint analysis. The current data conflict will ultimately provide deeper insights into ageing, Anderson predicts. ‘The fact the two studies were set up differently, asking the same question in different ways — I think we will gain maximally from that.’</p>
', 1, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('fd10158d-9220-4a87-be0a-e46253c9962b', '4e0c8180-428c-4c81-8de5-85613e8dea80', 'Passage 3', '<p><span style="font-size: 14pt;"><strong>Travelling Plants</strong></span></p>
<p>Plants need to produce more individuals of their own kind, and these normally grow best from their parent. So plants need to travel, and they do so in a variety of ways.</p>
<p>In an English woodland, the blackberry puts out exploratory stems, which curve upwards, waving slowly as though searching. If they touch another plant, they begin to advance directly and purposefully. To us, their motion is invisible, but for a plant it’s an extraordinary rate – around five centimetres a day. When a stem makes contact with the ground, it puts down small rootlets, and starts to extract nutriment.</p>
<p>The silverweed is equally effective, putting out travelling stems that advance horizontally, creeping at low level through the mat of rootlets and dead vegetation formed by other plants.</p>
<p>In meadows, fescue grass is notable for annexing land from other less robust and aggressive species. The genetic fingerprints of its leaves and stems taken two hundred metres apart have proved, in some instances, to be identical. This must mean that one particularly vigorous plant has increased its territory year after year until now, after perhaps a century, it has become the largest plant in the entire meadow.</p>
<p>The bird-cage plant grows among sand dunes, in the deserts of the American west, and puts down long roots to search for water. But if the sand blows away, the plant’s roots may shrivel up, the plant dies, and the stems form a hollow sphere. With no roots to anchor it, the wind blows it across the sand for several kilometres. Eventually it rolls into a sheltered site, allowing the seeds inside to germinate.</p>
<p>A few plants don’t need external assistance to distribute their seeds. The Mediterranean squirting cucumber fills with a slimy juice as it ripens. Eventually the juice shifts so violently that the cucumber bursts off its stalk and shoots off six metres through the air, leaving a trail of slime and seeds behind it.</p>
<p>One of the most dramatic detonating seed-containers belongs to a Brazilian tree known as monkey’s dinner-bell. The side of the seed pod facing the sun dries out, causing an explosion which can hurl the seeds over twelve metres. The bang is enough to convince nervous strangers in the forest that they’re under attack.</p>
<p>It’s particularly important for trees to eject their seeds from away enough to gain adequate light and nutriment. This is helped by the height of the tree, and in some cases by fitting their seeds with wings. Sycamore seeds have a single large wing, so a single spin makes it easy for them to travel far. Others, such as the willow, bear seeds with hairs that catch the wind and may fly far from their parent.</p>
<p>Instead of using wind or water as carriers, many plants use animals. The South African grappling plant, a low-growing creeper, relies on its seeds being trodden on. Its seed capsules have arms ending in hooks that are so sharp and strong, and point in so many directions, that when the foot of an elephant or rhino descends on one, the capsule becomes attached, and is carried by the animal.</p>
<p>Other plants reward their carriers instead of hurting them. Many plants that grow in the heathland of South Africa provide their seeds with an edible covering which animals find particularly attractive. These collect the seeds and carry them down to their underground nests, where they eat the covering, leaving the seeds themselves in an ideal position to germinate.</p>
<p>Fruit seeds are completely enclosed with such a generous edible reward that the animal-carrier is encouraged to swallow both together. While the plant is constructing the seeds, the flesh of the unripe fruit is sour, and animals learn not to eat it. But once the seeds are fully developed, the sap becomes sweet, and the fruit signals the fact that the seeds are now ready for transport by changing colour. Animals understand the signals well. They now eat the fruit, and carry the seed away inside their stomachs, to be ejected at a distance. Not all seeds have to pass through the entire digestive tract to be transported, though. The quetzal, a Central American bird, feeds on the wild avocado, swallowing it whole. It eventually regurgitates the stone, which then has a chance to take root and produce a new plant.</p>
<p>Passage through an animal’s gut is essential for some seeds, however. When the acacia of East Africa produces its seed-bearing pods, beetles fly in, lay eggs, and as the grubs hatch, they feed on the acacia seeds. The seeds can only grow if an elephant, or other animal, eats the pod, as its digestive juices kill the eggs. Eventually the seeds return to the outside world in the animal’s droppings, and can germinate.</p>
<p>While the seeds of pine trees are developing, they’re protected inside cones. When the seeds are ripe, one bird, the nut-cracker, is particularly skilful at picking them out. Those it can’t eat immediately it buries, providing the seed with ideal growing conditions. But two out of every three seeds that the bird buries, it never finds again, so the tree uses a strategy of sacrificing a few of its seeds and relying on the poor memory of the courier who hides and conceals them. So in one way or another, many seeds reach destinations where they can start their lives away from the environmental dominance of their parents.</p>
', 2, NULL, NULL, NULL);
