INSERT INTO public.passages VALUES ('ec7ef32f-dc7a-4cbf-af79-816eb1d27235', '387d80e9-eee6-4b7e-b11e-ddc73abd4013', 'part 4', '', 3, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('b994b6ce-d83c-47c9-8f16-d98446ed3878', '92f69ba8-2c9a-4292-8d96-ae5501ec14f5', 'SECTION 1', '<p><strong>Read the text below and answer Questions 1–7.</strong></p>
<p style="text-align: center;" data-section-id="1rpyvkl" data-start="189" data-end="249"><span style="font-size: 14pt;"><strong data-start="192" data-end="249">Gobridge Tramlink – Frequently Asked Questions (FAQs)</strong></span></p>
<p style="text-align: center;">Here are some of the frequently asked questions about the tram service in Gobridge town</p>
<p data-section-id="1foj227" data-start="345" data-end="375"><strong>When do the trams run?</strong></p>
<p>Gobridge Tramlink operates a network of trams that run throughout the year and provide links to main services, stations and the airport. Timetables are reviewed in October and March, and may alter slightly so check before you travel. Our first tram from the city centre leaves from Marvin Square at 6.30 am, half an hour after the first city bus service.</p>
<p data-section-id="1s37cj1" data-start="738" data-end="780"><strong>Can I get a tram from the airport?</strong></p>
<p>Trams from the airport to the city centre start running at 6.15 am and leave every fifteen minutes until 7.30 pm when the evening schedule takes over. Trams then run to the main railway station at 35-minute intervals and end at 11.35 pm. If your flight arrives later than this, the number 207 airport bus runs every hour through the night.</p>
<p data-section-id="1qsi5m3" data-start="1128" data-end="1174"><strong>What do I do if I don’t have a ticket?</strong></p>
<p>Tickets are not sold by anyone on the tram. Ticket vending machines are located at all tram shelters. Check your route and make sure you buy the correct price ticket. If the vending machine does not work, you should push the red button on the machine and speak into the microphone. A member of staff will either fix the machine straight away or contact the tram inspector onboard your tram. He or she cannot sell you a ticket, but you will not be obliged to pay the £8 on-board fine for not having one.</p>
<p data-section-id="1jqcxes" data-start="1685" data-end="1724"><strong>Can I take my bike on the tram?</strong></p>
<p>Each tram is licensed to carry a maximum of two bicycles, though drivers may refuse to allow cyclists to get on if the tram is crowded. Bicycles may only be taken on the trams during off-peak travel periods: up to 7.30 am, between 10 am and 2.30 pm and after 7 pm. Festivals and other large events may also mean that bicycles are prohibited as trams carry extra passengers at these times. Once on board, riders should remain with their bicycles throughout the journey and ensure they do not obstruct the entrance, exit or any other area of public access.</p>
<p><strong>Read the text below and answer Questions 8–14.</strong></p>
<p style="text-align: center;" data-section-id="n5806m" data-start="2353" data-end="2379"><span style="font-size: 14pt;"><strong data-start="2356" data-end="2377">Adorable knitwear</strong></span></p>
<p style="text-align: center;">Online customer reviews</p>
<p><strong>A Mary-Anne</strong></p>
<p>I spent a while thinking about buying this sweater because of the price, but I’m glad I finally did. It’s a long sweater but that’s good as I’m quite tall. I normally find that the sleeves are too short when I try on a top, but not with this one. I tend to take medium but went for large, which was a wise decision as there is plenty of room for a T-shirt underneath when I wear it with jeans.</p>
<p data-section-id="3mfz69" data-start="2835" data-end="2851"><strong>B Davina</strong></p>
<p>These sweaters are an ideal weight for office wear. The purple one is pretty, though I expected a lighter shade from the picture. I wear a US size 12 / UK 16, and the medium is big enough to fit over a shirt with room to spare. It has long sleeves that I love to roll up at the wrist. I’m now trying to resist the temptation to buy it in grey too.</p>
<p data-section-id="w4e7m4" data-start="3207" data-end="3221"><strong>C Naga</strong></p>
<p>This knitted sweater looks great in the pictures. I ordered the olive green with stripes and, although I wasn’t sure it was going to look right on me, I was pleasantly surprised when I put it on. It’s very soft and I love the long past-the-wrist sleeves too. I opted for the medium, but it was too tight so I exchanged it.</p>
<p data-section-id="1y71sgu" data-start="3552" data-end="3567"><strong>D Libby</strong></p>
<p>This is the third of your sweaters that I’ve bought over the past two years. It’s true to size and perfect for the winter months, though I should add that its loose knit means it’s best to avoid playing with cats or young dogs when you’re wearing it as they could pull threads in the body or sleeves.</p>
<p data-section-id="1m6n954" data-start="3876" data-end="3891"><strong>E Laura</strong></p>
<p>I couldn’t decide which colour to get so I bought the deep blue and the charcoal grey, with every intention of sending one of them back. That didn’t happen, of course! I would say both colours match the online pictures. I bought size small, and the length is perfect for me, despite the unnecessarily long sleeves! These sweaters are lovely to wear with jeans but also stylish enough to wear to work.</p>', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('8850f39d-c4f0-4516-a2cd-0234e74bda36', '92f69ba8-2c9a-4292-8d96-ae5501ec14f5', 'SECTION 2', '<p><strong>Read the text below and answer Questions 15–21.</strong></p>
<p style="text-align: center;" data-section-id="1q0yeeq" data-start="175" data-end="210"><span style="font-size: 14pt;"><strong data-start="178" data-end="210">How to become a great leader</strong></span></p>
<p>Stepping into a new management role can be unnerving. Here’s how to inspire your team:</p>
<p>Set the tone of your leadership style from the outset. Be confident, self-assured and respectful with everyone you meet. Speak as you want to be spoken to, and remember to listen. The first few weeks is when people develop their perceptions of you, so work hard to earn their trust. This will be key to effective change and progress.</p>
<p>Part of a leader’s brief is to set bold goals. They could take years to achieve, but they need to be specific enough that everyone in the organisation understands them, buys into them and is willing to work together to achieve them.</p>
<p>Don’t do everything yourself. Great leaders surround themselves with talented individuals and they should trust them to make things happen. If things need changing, tell people and involve them in making the changes by participating in the design of a new strategy. If the team is too cautious to embrace change, give them one more chance but be clearer about what you want.</p>
<p>Stamp out the ‘them and us’ culture. In many organisations, employees feel distant from senior management. The message must be plain: we all work together, but leaders need to work hard to ensure this filters through to everyone in the organisation.</p>
<p>Allow time for innovation. It’s important to give staff time to come up with new ideas and solutions that will fix new problems. However, be clear that a decision is expected; set a time limit and stick to it.</p>
<p>It is likely that the formula that makes the business you are managing successful will have been created many years ago – but it’s important to remember how the business started. Honour those early pioneers and instil a sense of pride across the organisation.</p>
<p>Leaders need to accept that some risk may be required if the situation calls for it. Playing it safe is never a good business rule, and leaders must make sure their business stays ahead by being prepared to act quickly.</p>
<p>Show you are passionate and enthusiastic. People spend a large part of their lives working for an organisation, and having a leader who is genuinely thrilled about its future is hugely inspiring.</p>
<p><strong>Read the text below and answer Questions 22–27.</strong></p>
<p style="text-align: center;"><span style="font-size: 14pt;"><strong data-start="2465" data-end="2514">Resigning from a job in a professional manner</strong></span></p>
<p>When you take the decision to resign and move on to another job, you might really want to dance your way out of the door, or get your own back by criticising your boss to the whole office. But you need to resist these temptations because in future you might find you’re working with your ex-line manager or other colleagues in a different company.</p>
<p><strong data-start="2874" data-end="2903">Letting your manager know</strong></p>
<p>Show courtesy by telling your boss first. Request a meeting to say that you’re leaving, following up soon after with an official letter. Before the meeting with your boss, write a list of ongoing tasks along with status updates and suggestions concerning completion. Use the meeting to clarify any other points, such as your notice period and leaving date, and how you will inform others (colleagues or external clients, contacts and suppliers). Ask about a reference too; your employer may only supply the most basic type but your line manager might also give you a more personal one. Making sure you get a good one can make subsequent job hunting less stressful.</p>
<p><strong data-start="3580" data-end="3595">Preparation</strong></p>
<p>Work out how you can ensure a smooth transition and minimise disruption to your employer. There may be a range of things you can do to hand over professionally, such as completing projects, working out the priorities with your line manager, and leaving clear documentation for the successor in your post concerning processes or software.</p>
<p><strong data-start="3945" data-end="3975">Your letter of resignation</strong></p>
<p>Keep your letter short. You don’t need to give lots of explanations or justification for why you’re leaving. Don’t be tempted to address the feelings of the company or your boss, either. Instead, thanking your employer for the job and mentioning what you appreciated about it is a graceful touch. Here’s an idea of what to include:</p>
<ul data-start="4310" data-end="4831">
<li data-section-id="1e6ztgq" data-start="4310" data-end="4433">– First paragraph – the basicsInform the employer that you wish to resign and confirm the agreed final date at work.</li>
<li data-section-id="1042ej6" data-start="4435" data-end="4710">– Second paragraph – thank your employerMention any particular career-building projects you worked on or opportunities to develop skills and contribute to the employer’s goals and successes. You can also mention your appreciation at being able to work in a great team.</li>
<li data-section-id="9ufhf4" data-start="4712" data-end="4831">– Third paragraph – handoverState your willingness to finish existing projects and hand over your work smoothly.</li>
</ul>', 1, NULL, NULL, 15);
INSERT INTO public.passages VALUES ('d3611042-d30e-4c59-b13c-3bf1a9293da6', 'fc249412-1be8-4993-aea6-b1901b7ab31b', 'Passage 3', '<p style="text-align: left;"><span style="font-size: 14pt;"><strong>Termite Mounds </strong></span></p>
<p style="text-align: left;"><strong>{iii. reconsidering the termite’s reputation}</strong></p>
<p style="text-align: left;">To most of us, termites are destructive insects which can cause damage on a devastating scale. But according to Dr Rupert Soar of Loughborough University’s School of Mechanical and Manufacturing Engineering, these pests may serve a useful purpose for us after all. His multi-disciplinary team of British and American engineers and biologists have set out to investigate the giant mounds built by termites in Namibia, in sub-Saharan Africa, as part of the most extensive study of these structures ever taken.</p>
<p style="text-align: left;"><strong>{vii. the astonishing physical dimensions of the termite mound} </strong></p>
<p style="text-align: left;">Termite mounds are impressive for their size alone; typically they are three metres high, and some as tall as eight metres by found. They also reach far into the earth, where the insects ‘mine’ their building materials, carefully selecting each grain of sand they use. The termite’s nest is contained in the central cavity of the mound, safely protected from the harsh environment outside. The mound itself is formed of an intricate lattice of tunnels, which spilt into smaller and smaller tunnels, much like a person’s blood vessels.</p>
<p style="text-align: left;"><strong>{iv. principal functions of the termite mound} </strong></p>
<p style="text-align: left;">This complex system of tunnels draws in air from the outside, capturing wind energy to drive it through the mound. It also serves to expel spent respiratory gases from the nest to prevent the termites from suffocating, so ensuring them a continuous provision of fresh, breathable air. So detailed is the design that the nest stays within three degrees of a constant temperature, despite variations on the outside of up to 500C, from blistering heat in the daytime to below freezing on the coldest nights. The mound also automatically regulates moisture in the air, by means of best its underground ‘cellar’, and evaporation from the top of the mound. Some colonies even had ‘chimneys’ at a height of 20m to control moisture less in the hottest regions of sub-Saharan Africa.</p>
<p style="text-align: left;"><strong>{ix. a mutually beneficial relationship}</strong></p>
<p style="text-align: left;">Furthermore, the termites have evolved in such a way as to outsource some of their biological functions. Part of their digestive process in camera out by a fungus, which they ‘farm’ inside the mound. This fungus, which is found nowhere else on earth, thrives in the constant and optimum environment of the mound. The termites feed the fungus with slightly chewed wood pulp, which the fungus then breaks down into a digestible sugary food to provide the insects with energy, and cellulose which they use for building. And, although the termites must generate waste, none ever leaves the structure, indicating that there is also some kind of internal waste-recycling system.</p>
<p style="text-align: left;"><strong>{ii. challenging our assumptions about the nature of life}</strong></p>
<p style="text-align: left;">Scientists are so excited by the mounds that they have labelled them a ‘super organism’ because, in Soar’s word. “They dance on the edge of what we would perceive to cool down, or if you’re too cold you need to thrive: that’s called homeostasis. What the termites have done is to move homeostatic function away from their body, into the structure in which they live. ‘As more information comes to light about the unique features of termite mounds, we may ultimately need to redefine our understanding of what constitutes a ‘living’ organism.</p>
<p style="text-align: left;"><strong>{i. methods used to investigate termite mound formation}</strong></p>
<p style="text-align: left;">To reveal the structure of the mounds, Soar’s team begins by filling and covering their plaster of Paris, a chalky white paste based on the mineral gypsum, which becomes rock-solid when dry. The researcher’s hen carves the plaster of Paris into half-millimatre-thick slices, and photograph them sequentially. Once the pictures are digitally scanned, computer technology is able to recreate complex three-dimensional images of the mounds. These models have enabled the team to map termite architecture at a level of detail never before attained.</p>
<p style="text-align: left;"><strong>{vi. some potential benefits of understanding termite architecture}</strong></p>
<p style="text-align: left;">Soar hopes that the models will explain how termite mounds create a self-regulating living environment which manages to respond to changing internal and external conditions without drawing on any outside source of power. If they do, the findings could be invaluable in informing future architectural design, and could inspire buildings that are self-sufficient, environmentally, and cheap to run. ‘As we approach a world of climate change, we need temperatures to rise, he explains, there will not be enough fuel to drive air conditioners around the world. It is hoped, says Soar, ‘ that the findings will provide clues that aid the ultimate development of new kinds of human habitats, suitable for a variety of arid, hostile environments not only on the earth but maybe one day on the moon and beyond.</p>', 0, NULL, NULL, 27);
INSERT INTO public.passages VALUES ('79a1889f-4582-4550-ada0-71bb52f9bb4f', 'c9f9f7ee-54e3-47f6-95b1-2a50f525e71c', 'PART 1', '', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('e06f9fa7-4d38-4e89-90b9-ed2dd66bf6af', 'c9f9f7ee-54e3-47f6-95b1-2a50f525e71c', 'PART 2', '', 1, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('86f1b19c-d59b-4b8e-89b5-6d8216bef9ae', 'c9f9f7ee-54e3-47f6-95b1-2a50f525e71c', 'PART 3', '', 2, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('376d684b-ef75-4afd-85d9-7ed3d95c3632', 'c9f9f7ee-54e3-47f6-95b1-2a50f525e71c', 'PART 4', '', 3, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('de6a1cd5-af53-4f9b-a3f1-cbfd3ad5d816', '576f903e-a9c5-4124-b5d0-7475f077dbad', 'Part 4', '', 0, NULL, NULL, 31);
INSERT INTO public.passages VALUES ('e8167d81-68e7-442d-9f95-a1cbb0b016e1', 'c9dcc83f-fb8a-4b67-a987-5e3491146cab', 'Part 1', '', 0, NULL, 427, NULL);
INSERT INTO public.passages VALUES ('d0161c1b-2bf2-48d5-84cd-fcfa9f229b9f', '65d4794b-6a7b-4d76-b213-a678471266d2', 'Passage 3', '<p><strong>A new stage in the study and teaching of history</strong></p>
<p>For hundreds of years, historians have relied on written or printed documents to provide the bulk of their source materials, and they have largely communicated with students and the wider public by writing books and journal articles. Today, however, the printed word is being superseded by a diversity of forms of communication, above all moving images on video or film.</p>
<p>A<br />
The development of this new form of communication is leading to a growing gap between the practice of professional historians based in academia, and the practice of those aiming to popularise the study of history among the general public, and to encourage people to create their own records for the future. On the one hand, there are mainstream academics who continue to use only the written word as they examine more and more fields with an ever-increasing number of sophisticated methodologies. On the other hand, film and video, especially as broadcast on television, are probably the major influence on the public’s consciousness of history, as they see film of events of fifty or a hundred years ago, events they had previously only read about.</p>
<p>B<br />
In a related development, a great many people now document local and family events in the form of videos; many schools, too, produce video yearbooks. All these visual records may well prove to be invaluable sources of information for future historians. The glaring contradiction is that the two approaches: the academic and what we might term the popular – have intersected very little: with a few notable exceptions, professional historians have tended to avoid involvement in television programmes about history, and have even less impact on what is being captured and preserved on video. And the potential of moving images has wielded negligible influence on the academic study of history.</p>
<p>C<br />
This gulf can be seen as resulting from the willingness or otherwise of individual historians to accept the validity of new forms of communication in the study of history. This is not the first time that the question has arisen. The study of history, as conceived of today, began with the transition from oral to literate culture, leading to the earliest written records and the earliest historical studies. A further turning point came with the advent of printing, which transformed scholarship, as the written or printed word lost its dominance. Historians faced with any new means of communication, ranging from simple audiotape to the printing press itself, have responded like computers. As yet, however, the use of moving images as a record of events and a source of historical evidence has hardly been accepted in its own right and gained parity of name.</p>
<p>D<br />
This does not mean that mainstream historians have totally ignored the advent of mass documentation of events: the majority seem perfectly ready to accept television documentaries or films as source materials. What they are reluctant to accept, it seems, is that moving images can be used as a way to both interpret and present history, in the same way as scholarly writing or oral narrative.</p>
<p>E<br />
Yet the number of historians using moving images in their research or teaching is very small. The barrier seems to be that the profession is structured around the medium of the written word, and is somewhat insulated in its academic setting. The use of moving images presents a substantial challenge to this setting and its assumptions. As a result, historians have rejected the training, institutions and motivations and the professional structures that would be needed in order to use images effectively. Above all, they have rejected the necessity to learn complicated new skills.</p>
<p>F<br />
So why should historians make this change? Clearly, films or videos of events and people can be used as solid evidence of the past, linked to the words of the narrator (whether a television presenter/historian or a university teacher giving a lecture) but carrying information in their own right. Film has reintroduced the oral form as a mode of research and communication for documenting historical events. Now, with moving images, people are reminded that oral communication is not limited to words: it also includes body language, expression and tone, and is embedded in a context. Little of this is evident in a written transcript. A further effect of video and film is that the narrator gives up some control and has less need to give explanations, while the viewer becomes involved in the process of interpreting and understanding history.</p>
<p>G<br />
Film or videotape can also aid historians by simplifying the work of the interviewer. Instead of trying to carry on an interview while simultaneously making notes about setting and other unspoken data, this new kind of historian can concentrate on the interview itself, and study the film later. The many benefits of using moving images as historical evidence easily outweigh worries about cost, technical skills, or the effect of a camera on a person telling his or her story. Moving images enhance the quality of historical research, and suggest new directions for historians to explore.</p>
', 0, NULL, NULL, NULL);
INSERT INTO public.passages VALUES ('05527816-3ef3-4aae-819f-925e36ed4ea6', 'e26b3c95-49ef-46e4-926b-37dcdc83d531', 'PASSAGE 3', '<p data-path-to-node="11"><span style="font-size: 14pt;"><strong data-path-to-node="11" data-index-in-node="0"> Risk taking</strong></span></p>
<p data-path-to-node="12"><strong data-path-to-node="12" data-index-in-node="0">A</strong> We run risks. Most of the time we ignore them; sometimes we stop and decide how to deal with them. That’s life. Risks arise in sports, in business, in personal relationships: they are present in the laboratory, in political calculations, everywhere. Acting individually, we often prefer to gain some benefit by accepting some danger. Acting collectively, we make similar trade-offs.</p>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">B</strong> When society must assess risks, and those risks can be clarified, at least in part, by science, technology or mathematics, the responsibility of the research community is to be clear and complete. But that is not always so easy. Furthermore, too few people pay full attention to the best evidence, much less modify their behaviors as a result. Even when the evidence of high risk is clear – about smoking, for instance – many will deny the risk, or dispute it, or accept that it exists and still go ahead. As a former cigarette smoker, I understand denial.</p>
<p data-path-to-node="14"><strong data-path-to-node="14" data-index-in-node="0">C</strong> Perhaps more important than the basic facts of risk are the varied perception of it. Hearing the prediction of 60% chance of rain, or recognizing the minuscule likelihood of becoming ill from a flu shot, most people understand the right responses: take your umbrella and get your flu shot. But some, fearfully but irrationally, go to the extreme and stay at home and avoid all contact with other people. Irrational decisions occasionally affect us all. When it comes to risks the best odds do not always influence people to make the correct decision.</p>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">D</strong> In her book, <em data-path-to-node="15" data-index-in-node="15">The Universe and the Teacup</em>, the science writer K. C. Cole reminds us that the risks of losing something and gaining something appear to be calculated in our minds according to quite different scales. People will risk a lot to prevent a loss, she notes; some people will rush into a burning building to save a pet. But they will usually risk very little if the only perceived outcome is a possible gain; many people won’t even risk pursuing an exciting job, if the current job, though unfulfilling, remains comfortable. That psychological mechanism, a desire to maintain the status quo, helps explain the high hurdles that any rational risk assessment must confront.</p>
<p data-path-to-node="16"><strong data-path-to-node="16" data-index-in-node="0">E</strong> Organizations face the same hurdles whenever they must cope with major shifts in policy. In his classic examination of the character of high-tech industry, <em data-path-to-node="16" data-index-in-node="158">Only the Paranoid Survive</em>, Andrew S. Grove gives a perceptive account of a crisis that took place during his tenure as Chairman of the Intel Corporation. The business environment for Intel and its competitors was transformed by a flood of low-cost memory chips from Japan, and Intel made the difficult decision to abandon its chip-making business. Such a period of change in the outside world is filled with danger. Grove notes, precisely because it is so easy for executives to try to disregard it or misinterpret the mounting evidence showing the profound risks of not making change at the very core. The distinction Cole cites is instructive here: one reason management and staff may not act is that they tend to focus on the potential gains of risking change (which they characterize as small), rather than on the catastrophic losses that risking change could prevent. The period becomes critical for a company, according to Grove, and deadly when unattended to.</p>
<p data-path-to-node="17"><strong data-path-to-node="17" data-index-in-node="0">F</strong> Likewise, at the national level, and even the global one, institutions tend to be more willing to take a risk if it means avoiding a loss, than they are if it might confer a gain. Almost everyone, for instance, sees the signs of ecological decay. Reid J. Lifset’s article, ‘Full Accounting’, describes newly developed techniques for clarifying which critical decision would have the highest pay-offs for the environment. Once these ‘leverage points’ as he calls them, are located, many environmental organizations will be willing to risk the resources needed to prevent further deterioration.</p>
<p data-path-to-node="18"><strong data-path-to-node="18" data-index-in-node="0">G</strong> More complicated are decisions by nations to invest broadly in educational research. Some governmental leaders are oblivious to the risks posed by under-investment, because the urgent needs of the present take precedence over actions that would give rise to even more substantial gains in the future. Their attitude is that today’s risks must be manageable, and that tomorrow’s gains are at the very least difficult to measure. Better consideration and decision making for what lies ahead is essential.</p>
<p data-path-to-node="19"><strong data-path-to-node="19" data-index-in-node="0">H</strong> Nevertheless, I confess to being an optimist. My glass is generally half full – though that may not help me handle risk. Whether one’s temperament is optimistic or pessimistic, everyone in our scientific and engineering community has a social responsibility: measure with care and portray with honesty the level of risk involved in any action or decision.</p>', 0, NULL, NULL, 27);
INSERT INTO public.passages VALUES ('2a64c3b0-92cc-47db-9fc6-aa53bf5413f3', 'c9dcc83f-fb8a-4b67-a987-5e3491146cab', 'Part 2', '', 1, 457, 776, 11);
